/// <summary>
/// Specifies the type of organizational calendar.
/// </summary>
public enum CalendarType
{
    /// <summary>Personal calendar owned by a single user.</summary>
    Personal = 1,

    /// <summary>Unit calendar scoped to an organizational position.</summary>
    Unit = 2,

    /// <summary>Organization-wide calendar.</summary>
    Organization = 3
}

/// <summary>
/// Specifies the visual and semantic type of a calendar event.
/// </summary>
public enum EventType
{
    /// <summary>Urgent or alert event.</summary>
    Urgent = 1,

    /// <summary>Private or confidential event.</summary>
    Private = 2,

    /// <summary>Confirmed or finalized event.</summary>
    Confirmed = 3,

    /// <summary>Meeting or appointment.</summary>
    Meeting = 4,

    /// <summary>Informational event.</summary>
    Info = 5,

    /// <summary>Deadline or scheduling marker.</summary>
    Deadline = 6
}

/// <summary>
/// Specifies the lifecycle status of a calendar event.
/// </summary>
public enum EventStatus
{
    /// <summary>Event is pending confirmation.</summary>
    Pending = 1,

    /// <summary>Event is confirmed.</summary>
    Confirmed = 2,

    /// <summary>Event was rejected.</summary>
    Rejected = 3,

    /// <summary>Event was cancelled.</summary>
    Cancelled = 4
}

/// <summary>
/// Specifies an invitee's RSVP response to a calendar event.
/// </summary>
public enum ParticipantResponse
{
    /// <summary>Invitee has not responded yet.</summary>
    Pending = 1,

    /// <summary>Invitee accepted the invitation.</summary>
    Accepted = 2,

    /// <summary>Invitee declined the invitation.</summary>
    Declined = 3,

    /// <summary>Invitee responded with tentative attendance.</summary>
    Maybe = 4
}

/// <summary>
/// Specifies the delivery channel for an event reminder.
/// </summary>
public enum ReminderChannel
{
    /// <summary>In-app notification reminder.</summary>
    InApp = 1,

    /// <summary>SMS reminder.</summary>
    Sms = 2
}

/// <summary>
/// Specifies how a calendar event repeats over time.
/// </summary>
public enum RecurrenceType
{
    /// <summary>Event does not repeat.</summary>
    None = 0,

    /// <summary>Repeats daily.</summary>
    Daily = 1,

    /// <summary>Repeats weekly.</summary>
    Weekly = 2,

    /// <summary>Repeats monthly.</summary>
    Monthly = 3,

    /// <summary>Repeats yearly.</summary>
    Yearly = 4,

    /// <summary>Repeats with a custom rule.</summary>
    Custom = 5
}

/// <summary>
/// Specifies which occurrences are affected when editing a recurring event series.
/// </summary>
public enum RecurrenceEditScope
{
    /// <summary>Only the selected occurrence.</summary>
    ThisOnly = 1,

    /// <summary>The selected occurrence and all following occurrences.</summary>
    ThisAndFollowing = 2,

    /// <summary>The entire recurring series.</summary>
    All = 3
}

/// <summary>
/// Specifies the status of an approval-based meeting request.
/// </summary>
public enum MeetingRequestStatus
{
    /// <summary>Request is awaiting target user approval.</summary>
    Pending = 1,

    /// <summary>Request was approved and converted to an event.</summary>
    Approved = 2,

    /// <summary>Request was rejected by the target user.</summary>
    Rejected = 3,

    /// <summary>Request was cancelled by the requester.</summary>
    Cancelled = 4
}

/// <summary>
/// Specifies the kind of item returned in a calendar range query.
/// </summary>
public enum RangeItemKind
{
    /// <summary>Calendar event item.</summary>
    Event = 1,

    /// <summary>Read-only task deadline item.</summary>
    TaskDeadline = 2
}

/// <summary>
/// Specifies the scope of a company holiday entry (backlog).
/// </summary>
public enum CalendarHolidayScope
{
    /// <summary>Organization-wide holiday.</summary>
    Organization = 1,

    /// <summary>Unit-scoped holiday.</summary>
    Unit = 2,

    /// <summary>Project-scoped holiday.</summary>
    Project = 3
}

/// <summary>
/// Specifies the type of bookable calendar resource (backlog).
/// </summary>
public enum CalendarResourceType
{
    /// <summary>Meeting room.</summary>
    Room = 1,

    /// <summary>Equipment resource.</summary>
    Equipment = 2,

    /// <summary>Other resource type.</summary>
    Other = 3
}

