using Domain.Models.Organization;

namespace Domain.Models;

/// <summary>
/// Represents a personal, unit, or organization calendar container.
/// </summary>
public class Calendar : Entity<int>
{
    /// <summary>Gets or sets the calendar display title.</summary>
    public string Title { get; set; } = string.Empty;

    /// <summary>Gets or sets the calendar type.</summary>
    public CalendarType Type { get; set; }

    /// <summary>Gets or sets the owner user id for personal calendars.</summary>
    public int? OwnerUserId { get; set; }

    /// <summary>Gets or sets the owner user navigation property.</summary>
    public AppUser? OwnerUser { get; set; }

    /// <summary>Gets or sets the org position id for unit calendars.</summary>
    public int? OrgPositionId { get; set; }

    /// <summary>Gets or sets the org position navigation property.</summary>
    public OrgPosition? OrgPosition { get; set; }

    /// <summary>Gets or sets the display color hex value.</summary>
    public string Color { get; set; } = "#2196F3";

    /// <summary>Gets or sets whether this is the user's default personal calendar.</summary>
    public bool IsDefault { get; set; }

    /// <summary>Gets or sets events contained in this calendar.</summary>
    public IList<CalendarEvent> Events { get; set; } = [];

    /// <summary>
    /// Creates a default personal calendar for the given user.
    /// </summary>
    /// <param name="userId">Owner user id.</param>
    /// <returns>A new personal calendar instance.</returns>
    public static Calendar CreateDefaultPersonal(int userId) =>
        new()
        {
            Title = "تقویم من",
            Type = CalendarType.Personal,
            OwnerUserId = userId,
            Color = "#2196F3",
            IsDefault = true
        };
}

namespace Domain.Models;

/// <summary>
/// Represents a calendar event (meeting, deadline, etc.).
/// </summary>
public class CalendarEvent : Entity<int>
{
    /// <summary>Gets or sets the parent calendar id.</summary>
    public int CalendarId { get; set; }

    /// <summary>Gets or sets the parent calendar.</summary>
    public Calendar Calendar { get; set; } = null!;

    /// <summary>Gets or sets the creator user id.</summary>
    public int CreatedByUserId { get; set; }

    /// <summary>Gets or sets the creator user.</summary>
    public AppUser CreatedByUser { get; set; } = null!;

    /// <summary>Gets or sets the event title.</summary>
    public string Title { get; set; } = string.Empty;

    /// <summary>Gets or sets the optional description.</summary>
    public string? Description { get; set; }

    /// <summary>Gets or sets the optional location.</summary>
    public string? Location { get; set; }

    /// <summary>Gets or sets the event type.</summary>
    public EventType Type { get; set; }

    /// <summary>Gets or sets the event status.</summary>
    public EventStatus Status { get; set; } = EventStatus.Confirmed;

    /// <summary>Gets or sets the start date/time (UTC).</summary>
    public DateTime StartAt { get; set; }

    /// <summary>Gets or sets the end date/time (UTC).</summary>
    public DateTime EndAt { get; set; }

    /// <summary>Gets or sets whether the event spans the full day.</summary>
    public bool IsAllDay { get; set; }

    /// <summary>Gets or sets whether the event is personal (privacy-sensitive).</summary>
    public bool IsPersonal { get; set; }

    /// <summary>Gets or sets whether details are visible only to participants.</summary>
    public bool VisibleOnlyToParticipants { get; set; }

    /// <summary>Gets or sets the recurrence rule when the event repeats.</summary>
    public CalendarRecurrence? Recurrence { get; set; }

    /// <summary>Gets or sets series occurrence exceptions.</summary>
    public IList<CalendarEventException> Exceptions { get; set; } = [];

    /// <summary>Gets or sets invited participants.</summary>
    public IList<CalendarParticipant> Participants { get; set; } = [];

    /// <summary>Gets or sets scheduled reminders.</summary>
    public IList<CalendarReminder> Reminders { get; set; } = [];
}

namespace Domain.Models;

/// <summary>
/// Represents an invitee and RSVP state for a calendar event.
/// </summary>
public class CalendarParticipant : Entity<int>
{
    /// <summary>Gets or sets the parent event id.</summary>
    public int EventId { get; set; }

    /// <summary>Gets or sets the parent event.</summary>
    public CalendarEvent Event { get; set; } = null!;

    /// <summary>Gets or sets the invited user id.</summary>
    public int UserId { get; set; }

    /// <summary>Gets or sets the invited user.</summary>
    public AppUser User { get; set; } = null!;

    /// <summary>Gets or sets the invitee response.</summary>
    public ParticipantResponse Response { get; set; } = ParticipantResponse.Pending;
}

namespace Domain.Models;

/// <summary>
/// Represents a reminder scheduled before a calendar event starts.
/// </summary>
public class CalendarReminder : Entity<int>
{
    /// <summary>Gets or sets the parent event id.</summary>
    public int EventId { get; set; }

    /// <summary>Gets or sets the parent event.</summary>
    public CalendarEvent Event { get; set; } = null!;

    /// <summary>Gets or sets minutes before start to fire the reminder.</summary>
    public int OffsetMinutes { get; set; }

    /// <summary>Gets or sets the delivery channel.</summary>
    public ReminderChannel Channel { get; set; }

    /// <summary>Gets or sets whether the reminder was sent.</summary>
    public bool IsSent { get; set; }

    /// <summary>Gets or sets when the reminder was sent.</summary>
    public DateTime? SentAt { get; set; }
}

namespace Domain.Models;

/// <summary>
/// Represents the recurrence rule for a repeating calendar event.
/// </summary>
public class CalendarRecurrence : Entity<int>
{
    /// <summary>Gets or sets the parent event id.</summary>
    public int EventId { get; set; }

    /// <summary>Gets or sets the parent event.</summary>
    public CalendarEvent Event { get; set; } = null!;

    /// <summary>Gets or sets the recurrence type.</summary>
    public RecurrenceType Type { get; set; }

    /// <summary>Gets or sets the interval between occurrences.</summary>
    public int Interval { get; set; } = 1;

    /// <summary>Gets or sets comma-separated week day indices (0=Sunday) for weekly recurrence.</summary>
    public string? WeekDays { get; set; }

    /// <summary>Gets or sets the recurrence end date.</summary>
    public DateTime? EndDate { get; set; }

    /// <summary>Gets or sets the maximum number of occurrences.</summary>
    public int? OccurrenceCount { get; set; }
}

namespace Domain.Models;

/// <summary>
/// Represents an override or cancellation for a single occurrence in a recurring series.
/// </summary>
public class CalendarEventException : Entity<int>
{
    /// <summary>Gets or sets the parent series event id.</summary>
    public int EventId { get; set; }

    /// <summary>Gets or sets the parent series event.</summary>
    public CalendarEvent Event { get; set; } = null!;

    /// <summary>Gets or sets the original occurrence date being overridden.</summary>
    public DateTime OccurrenceDate { get; set; }

    /// <summary>Gets or sets whether this occurrence is cancelled.</summary>
    public bool IsCancelled { get; set; }

    /// <summary>Gets or sets overridden start time when rescheduled.</summary>
    public DateTime? OverrideStartAt { get; set; }

    /// <summary>Gets or sets overridden end time when rescheduled.</summary>
    public DateTime? OverrideEndAt { get; set; }
}

namespace Infrastructure.Data.Configuration.Calendar;

public class CalendarConfiguration : IEntityTypeConfiguration<Calendar>
{
    public void Configure(EntityTypeBuilder<Calendar> builder)
    {
        builder.Property(x => x.Title)
            .IsRequired()
            .HasMaxLength(200);

        builder.Property(x => x.Color)
            .IsRequired()
            .HasMaxLength(20);

        builder.HasOne(x => x.OwnerUser)
            .WithMany()
            .HasForeignKey(x => x.OwnerUserId)
            .OnDelete(DeleteBehavior.Restrict);

        builder.HasOne(x => x.OrgPosition)
            .WithMany()
            .HasForeignKey(x => x.OrgPositionId)
            .OnDelete(DeleteBehavior.Restrict);
    }
}

namespace Infrastructure.Data.Configuration.Calendar;

public class CalendarEventConfiguration : IEntityTypeConfiguration<CalendarEvent>
{
    public void Configure(EntityTypeBuilder<CalendarEvent> builder)
    {
        builder.Property(x => x.Title)
            .IsRequired()
            .HasMaxLength(200);

        builder.Property(x => x.Description)
            .HasMaxLength(2048);

        builder.Property(x => x.Location)
            .HasMaxLength(500);

        builder.HasOne(x => x.Calendar)
            .WithMany(x => x.Events)
            .HasForeignKey(x => x.CalendarId)
            .OnDelete(DeleteBehavior.Restrict);

        builder.HasOne(x => x.CreatedByUser)
            .WithMany()
            .HasForeignKey(x => x.CreatedByUserId)
            .OnDelete(DeleteBehavior.Restrict);

        builder.HasOne(x => x.Recurrence)
            .WithOne(x => x.Event)
            .HasForeignKey<CalendarRecurrence>(x => x.EventId)
            .OnDelete(DeleteBehavior.Cascade);
    }
}

namespace Infrastructure.Data.Configuration.Calendar;

public class CalendarParticipantConfiguration : IEntityTypeConfiguration<CalendarParticipant>
{
    public void Configure(EntityTypeBuilder<CalendarParticipant> builder)
    {
        builder.HasOne(x => x.Event)
            .WithMany(x => x.Participants)
            .HasForeignKey(x => x.EventId)
            .OnDelete(DeleteBehavior.Cascade);

        builder.HasOne(x => x.User)
            .WithMany()
            .HasForeignKey(x => x.UserId)
            .OnDelete(DeleteBehavior.Restrict);

        builder.HasIndex(x => new { x.EventId, x.UserId })
            .IsUnique();
    }
}

namespace Infrastructure.Data.Configuration.Calendar;

public class CalendarReminderConfiguration : IEntityTypeConfiguration<CalendarReminder>
{
    public void Configure(EntityTypeBuilder<CalendarReminder> builder)
    {
        builder.HasOne(x => x.Event)
            .WithMany(x => x.Reminders)
            .HasForeignKey(x => x.EventId)
            .OnDelete(DeleteBehavior.Cascade);
    }
}

namespace Infrastructure.Data.Configuration.Calendar;

public class CalendarRecurrenceConfiguration : IEntityTypeConfiguration<CalendarRecurrence>
{
    public void Configure(EntityTypeBuilder<CalendarRecurrence> builder)
    {
        builder.Property(x => x.WeekDays)
            .HasMaxLength(50);
    }
}

namespace Infrastructure.Data.Configuration.Calendar;

public class CalendarEventExceptionConfiguration : IEntityTypeConfiguration<CalendarEventException>
{
    public void Configure(EntityTypeBuilder<CalendarEventException> builder)
    {
        builder.HasOne(x => x.Event)
            .WithMany(x => x.Exceptions)
            .HasForeignKey(x => x.EventId)
            .OnDelete(DeleteBehavior.Cascade);

        builder.HasIndex(x => new { x.EventId, x.OccurrenceDate })
            .IsUnique();
    }
}

