using Application.Services;
using Domain.Models;

namespace Application.Features.App.Calendar;

/// <summary>
/// Shared authorization and visibility helpers for calendar features.
/// </summary>
public static class CalendarAccessHelper
{
    /// <summary>
    /// Returns calendar ids the user belongs to via position membership.
    /// </summary>
    public static async Task<HashSet<int>> GetUserPositionIdsAsync(
        IApplicationDbContext context,
        int userId,
        CancellationToken cancellationToken)
    {
        var ids = await context.PositionUsers
            .AsNoTracking()
            .Where(x => x.UserId == userId)
            .Select(x => x.OrgPositionId)
            .ToListAsync(cancellationToken);

        return ids.ToHashSet();
    }

    /// <summary>
    /// Determines whether the user can write to the calendar.
    /// </summary>
    public static async Task<bool> CanWriteAsync(
        Calendar calendar,
        int userId,
        ICurrentUserService currentUser,
        HashSet<int> userPositionIds,
        CancellationToken cancellationToken)
    {
        return calendar.Type switch
        {
            CalendarType.Personal => calendar.OwnerUserId == userId,
            CalendarType.Unit => calendar.OrgPositionId.HasValue
                && userPositionIds.Contains(calendar.OrgPositionId.Value),
            CalendarType.Organization => await currentUser.IsAdmin(),
            _ => false
        };
    }

    /// <summary>
    /// Determines whether the user can view the calendar.
    /// </summary>
    public static bool CanView(Calendar calendar, int userId, HashSet<int> userPositionIds) =>
        calendar.Type switch
        {
            CalendarType.Personal => calendar.OwnerUserId == userId,
            CalendarType.Unit => calendar.OrgPositionId.HasValue
                && userPositionIds.Contains(calendar.OrgPositionId.Value),
            CalendarType.Organization => true,
            _ => false
        };

    /// <summary>
    /// Maps a calendar entity to a DTO with write permission for the current user.
    /// </summary>
    public static async Task<CalendarDto> ToDtoAsync(
        Calendar calendar,
        int userId,
        ICurrentUserService currentUser,
        HashSet<int> userPositionIds,
        CancellationToken cancellationToken) =>
        new()
        {
            Id = calendar.Id,
            Title = calendar.Title,
            Type = calendar.Type,
            OwnerUserId = calendar.OwnerUserId,
            OrgPositionId = calendar.OrgPositionId,
            Color = calendar.Color,
            CanWrite = await CanWriteAsync(calendar, userId, currentUser, userPositionIds, cancellationToken)
        };

    /// <summary>
    /// Validates recurrence input per contract rules.
    /// </summary>
    public static Error? ValidateRecurrence(RecurrenceDto? recurrence)
    {
        if (recurrence is null || recurrence.Type == RecurrenceType.None)
            return null;

        if (recurrence.Interval < 1)
            return EventErrors.InvalidRecurrence;

        if (recurrence.Type == RecurrenceType.Weekly
            && (recurrence.WeekDays is null || recurrence.WeekDays.Count == 0))
            return EventErrors.InvalidRecurrence;

        var hasEndDate = recurrence.EndDate.HasValue;
        var hasCount = recurrence.OccurrenceCount.HasValue;

        if (hasEndDate == hasCount)
            return EventErrors.InvalidRecurrence;

        if (hasCount && recurrence.OccurrenceCount < 1)
            return EventErrors.InvalidRecurrence;

        return null;
    }

    /// <summary>
    /// Returns the default color for an event type.
    /// </summary>
    public static string GetEventTypeColor(EventType type) => type switch
    {
        EventType.Urgent => "#F44336",
        EventType.Private => "#9C27B0",
        EventType.Confirmed => "#4CAF50",
        EventType.Meeting => "#FF9800",
        EventType.Info => "#2196F3",
        EventType.Deadline => "#000000",
        _ => "#2196F3"
    };
}

