/// <summary>Handles calendar update.</summary>
public class CalendarUpdateCommandHandler(
    IApplicationDbContext context,
    ICurrentUserService currentUser)
    : IRequestHandler<CalendarUpdateCommand, Result<bool>>
{
    /// <inheritdoc />
    public async Task<Result<bool>> Handle(
        CalendarUpdateCommand request,
        CancellationToken cancellationToken)
    {
        try
        {
            var model = request.Model;
            var userId = currentUser.UserId();

            if (string.IsNullOrWhiteSpace(model.Title) || model.Title.Trim().Length < 2)
                return CalendarErrors.TitleTooShort;

            var entity = await context.Calendars
                .FirstOrDefaultAsync(x => x.Id == model.Id, cancellationToken);

            if (entity is null)
                return CalendarErrors.NotFound;

            var positionIds = await CalendarAccessHelper.GetUserPositionIdsAsync(
                context, userId, cancellationToken);

            if (!await CalendarAccessHelper.CanWriteAsync(
                    entity, userId, currentUser, positionIds, cancellationToken))
                return CalendarErrors.EditForbidden;

            entity.Title = model.Title.Trim();
            if (!string.IsNullOrWhiteSpace(model.Color))
                entity.Color = model.Color.Trim();

            await context.SaveChangesAsync(cancellationToken);
            return Result<bool>.Success(true);
        }
        catch (Exception ex)
        {
            Log.Error($"CalendarUpdate: {ex.Message}", ex);
            return Error.ServerError;
        }
    }
}

