namespace Application.Features.Command;

/// <summary>Handles calendar soft-delete.</summary>
public class CalendarDeleteCommandHandler(
    IApplicationDbContext context,
    ICurrentUserService currentUser,
    IDateTimeService dateTime)
    : IRequestHandler<CalendarDeleteCommand, Result<bool>>
{
    /// <inheritdoc />
    public async Task<Result<bool>> Handle(
        CalendarDeleteCommand request,
        CancellationToken cancellationToken)
    {
        try
        {
            var userId = currentUser.UserId();

            var entity = await context.Calendars
                .FirstOrDefaultAsync(x => x.Id == request.Id, cancellationToken);

            if (entity is null)
                return CalendarErrors.NotFound;

            if (entity.IsDefault && entity.Type == CalendarType.Personal)
                return CalendarErrors.DefaultPersonalCannotDelete;

            var positionIds = await CalendarAccessHelper.GetUserPositionIdsAsync(
                context, userId, cancellationToken);

            if (!await CalendarAccessHelper.CanWriteAsync(
                    entity, userId, currentUser, positionIds, cancellationToken))
                return CalendarErrors.DeleteForbidden;

            entity.IsDeleted = true;
            entity.DeleteDate = dateTime.Now;

            await context.SaveChangesAsync(cancellationToken);
            return Result<bool>.Success(true);
        }
        catch (Exception ex)
        {
            Log.Error($"CalendarDelete: {ex.Message}", ex);
            return Error.ServerError;
        }
    }
}

using Application.Services;
using Domain.Models;

namespace Application.Features.App.Calendar;

/// <summary>
/// Detects scheduling conflicts for calendar participants.
/// </summary>
public static class EventConflictHelper
{
    /// <summary>
    /// Returns the first conflicting user name among invitees, or null if none.
    /// </summary>
    public static async Task<string?> FindConflictUserNameAsync(
        IApplicationDbContext context,
        IEnumerable<int> userIds,
        DateTime startAt,
        DateTime endAt,
        int? excludeEventId,
        CancellationToken cancellationToken)
    {
        var ids = userIds.Distinct().ToList();
        if (ids.Count == 0)
            return null;

        var query = context.CalendarParticipants
            .AsNoTracking()
            .Where(p => ids.Contains(p.UserId))
            .Where(p => p.Event.Status == EventStatus.Confirmed)
            .Where(p => p.Event.StartAt < endAt && p.Event.EndAt > startAt);

        if (excludeEventId.HasValue)
            query = query.Where(p => p.EventId != excludeEventId.Value);

        var conflict = await query
            .Select(p => new { p.User.Name })
            .FirstOrDefaultAsync(cancellationToken);

        return conflict?.Name;
    }
}

