/// <summary>
/// Expands recurring events into occurrences within a date range.
/// </summary>
public static class RecurrenceExpander
{
    private const int MaxOccurrences = 500;

    /// <summary>
    /// Expands a recurring event into range items; non-recurring events return a single item.
    /// </summary>
    public static IEnumerable<(DateTime StartAt, DateTime EndAt, DateTime? OccurrenceDate)> Expand(
        CalendarEvent evt,
        DateTime rangeFrom,
        DateTime rangeTo)
    {
        if (evt.Recurrence is null || evt.Recurrence.Type == RecurrenceType.None)
        {
            if (evt.StartAt < rangeTo && evt.EndAt > rangeFrom)
                yield return (evt.StartAt, evt.EndAt, null);
            yield break;
        }

        var duration = evt.EndAt - evt.StartAt;
        var recurrence = evt.Recurrence;
        var occurrenceIndex = 0;
        var cursor = evt.StartAt;

        while (cursor < rangeTo && occurrenceIndex < MaxOccurrences)
        {
            if (recurrence.OccurrenceCount.HasValue && occurrenceIndex >= recurrence.OccurrenceCount.Value)
                break;

            if (recurrence.EndDate.HasValue && cursor > recurrence.EndDate.Value)
                break;

            var end = cursor + duration;
            var occurrenceDate = cursor.Date;

            var cancelled = evt.Exceptions.Any(x =>
                x.OccurrenceDate.Date == occurrenceDate && x.IsCancelled);

            if (!cancelled && cursor < rangeTo && end > rangeFrom)
            {
                var exception = evt.Exceptions.FirstOrDefault(x =>
                    x.OccurrenceDate.Date == occurrenceDate && !x.IsCancelled);

                var start = exception?.OverrideStartAt ?? cursor;
                var finish = exception?.OverrideEndAt ?? end;

                if (start < rangeTo && finish > rangeFrom)
                    yield return (start, finish, occurrenceDate);
            }

            cursor = GetNextOccurrence(cursor, recurrence);
            occurrenceIndex++;
        }
    }

    private static DateTime GetNextOccurrence(DateTime current, CalendarRecurrence recurrence) =>
        recurrence.Type switch
        {
            RecurrenceType.Daily => current.AddDays(recurrence.Interval),
            RecurrenceType.Weekly => GetNextWeekly(current, recurrence),
            RecurrenceType.Monthly => current.AddMonths(recurrence.Interval),
            RecurrenceType.Yearly => current.AddYears(recurrence.Interval),
            _ => current.AddDays(recurrence.Interval)
        };

    private static DateTime GetNextWeekly(DateTime current, CalendarRecurrence recurrence)
    {
        var days = ParseWeekDays(recurrence.WeekDays);
        if (days.Count == 0)
            return current.AddDays(7 * recurrence.Interval);

        for (var i = 1; i <= 7 * recurrence.Interval; i++)
        {
            var next = current.AddDays(i);
            if (days.Contains((int)next.DayOfWeek))
                return next;
        }

        return current.AddDays(7 * recurrence.Interval);
    }

    private static HashSet<int> ParseWeekDays(string? weekDays)
    {
        if (string.IsNullOrWhiteSpace(weekDays))
            return [];

        return weekDays
            .Split(',', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries)
            .Select(x => int.TryParse(x, out var d) ? d : -1)
            .Where(x => x >= 0 && x <= 6)
            .ToHashSet();
    }

    /// <summary>
    /// Serializes week day list for storage.
    /// </summary>
    public static string? SerializeWeekDays(IEnumerable<int>? weekDays) =>
        weekDays is null || !weekDays.Any()
            ? null
            : string.Join(',', weekDays.OrderBy(x => x));
}

