using Application.Errors;
using Application.Features.App.Calendar;
using Application.Services;

namespace Application.Features.Command;

/// <summary>Handles calendar event update including basic recurrence scope.</summary>
public class EventUpdateCommandHandler(
    IApplicationDbContext context,
    ICurrentUserService currentUser)
    : IRequestHandler<EventUpdateCommand, Result<bool>>
{
    /// <inheritdoc />
    public async Task<Result<bool>> Handle(
        EventUpdateCommand request,
        CancellationToken cancellationToken)
    {
        try
        {
            var model = request.Model;
            var userId = currentUser.UserId();

            if (model.EndAt <= model.StartAt)
                return EventErrors.InvalidTimeRange;

            if (model.Description?.Length > 2048)
                return EventErrors.DescriptionTooLong;

            var recurrenceError = CalendarAccessHelper.ValidateRecurrence(model.Recurrence);
            if (recurrenceError is not null)
                return recurrenceError;

            var entity = await context.CalendarEvents
                .Include(x => x.Calendar)
                .Include(x => x.Recurrence)
                .Include(x => x.Participants)
                .Include(x => x.Reminders)
                .Include(x => x.Exceptions)
                .FirstOrDefaultAsync(x => x.Id == model.Id, cancellationToken);

            if (entity is null)
                return EventErrors.NotFound;

            if (entity.CreatedByUserId != userId)
            {
                var positionIds = await CalendarAccessHelper.GetUserPositionIdsAsync(
                    context, userId, cancellationToken);

                if (!await CalendarAccessHelper.CanWriteAsync(
                        entity.Calendar, userId, currentUser, positionIds, cancellationToken))
                    return EventErrors.EditForbidden;
            }

            var hasRecurrence = entity.Recurrence is not null
                                && entity.Recurrence.Type != RecurrenceType.None;

            if (hasRecurrence && model.EditScope.HasValue && model.EditScope != RecurrenceEditScope.All)
            {
                if (!model.OccurrenceDate.HasValue)
                    return EventErrors.OccurrenceDateRequired;

                var occurrence = model.OccurrenceDate.Value;
                var existing = entity.Exceptions
                    .FirstOrDefault(x => x.OccurrenceDate.Date == occurrence.Date);

                if (existing is null)
                {
                    existing = new CalendarEventException
                    {
                        EventId = entity.Id,
                        OccurrenceDate = occurrence
                    };
                    entity.Exceptions.Add(existing);
                }

                existing.IsCancelled = false;
                existing.OverrideStartAt = model.StartAt;
                existing.OverrideEndAt = model.EndAt;

                await context.SaveChangesAsync(cancellationToken);
                return Result<bool>.Success(true);
            }

            var participantIds = model.ParticipantUserIds ?? entity.Participants.Select(x => x.UserId);
            var conflictName = await EventConflictHelper.FindConflictUserNameAsync(
                context,
                participantIds,
                model.StartAt,
                model.EndAt,
                entity.Id,
                cancellationToken);

            if (conflictName is not null)
                return EventErrors.Conflict(conflictName);

            entity.Title = model.Title.Trim();
            entity.Description = model.Description;
            entity.Location = model.Location;
            entity.Type = model.Type;
            entity.StartAt = model.StartAt;
            entity.EndAt = model.EndAt;
            entity.IsAllDay = model.IsAllDay;
            entity.IsPersonal = model.IsPersonal;
            entity.VisibleOnlyToParticipants = model.VisibleOnlyToParticipants;

            await context.SaveChangesAsync(cancellationToken);
            return Result<bool>.Success(true);
        }
        catch (Exception ex)
        {
            Log.Error($"EventUpdate: {ex.Message}", ex);
            return Error.ServerError;
        }
    }
}

