namespace Application.Features.Query;

/// <summary>Handles event detail query.</summary>
public class EventGetByIdQueryHandler(
    IApplicationDbContext context,
    ICurrentUserService currentUser)
    : IRequestHandler<EventGetByIdQuery, Result<EventDetailDto>>
{
    /// <inheritdoc />
    public async Task<Result<EventDetailDto>> Handle(
        EventGetByIdQuery request,
        CancellationToken cancellationToken)
    {
        try
        {
            var userId = currentUser.UserId();

            var entity = await context.CalendarEvents
                .AsNoTracking()
                .Include(x => x.Calendar)
                .Include(x => x.Participants).ThenInclude(x => x.User)
                .Include(x => x.Reminders)
                .Include(x => x.Recurrence)
                .FirstOrDefaultAsync(x => x.Id == request.Id, cancellationToken);

            if (entity is null)
                return EventErrors.NotFound;

            var isParticipant = entity.Participants.Any(x => x.UserId == userId);
            var isCreator = entity.CreatedByUserId == userId;

            if (entity.VisibleOnlyToParticipants && !isCreator && !isParticipant)
                return EventErrors.ViewForbidden;

            var dto = new EventDetailDto
            {
                Id = entity.Id,
                CalendarId = entity.CalendarId,
                Title = entity.Title,
                Description = entity.Description,
                Location = entity.Location,
                Type = entity.Type,
                StartAt = entity.StartAt,
                EndAt = entity.EndAt,
                IsAllDay = entity.IsAllDay,
                IsPersonal = entity.IsPersonal,
                VisibleOnlyToParticipants = entity.VisibleOnlyToParticipants,
                Status = entity.Status,
                CreatedByUserId = entity.CreatedByUserId,
                Participants = entity.Participants.Select(p => new ParticipantDto
                {
                    UserId = p.UserId,
                    FullName = p.User.Name,
                    Response = p.Response
                }).ToList(),
                Reminders = entity.Reminders.Select(r => new ReminderDto
                {
                    Id = r.Id,
                    OffsetMinutes = r.OffsetMinutes,
                    Channel = r.Channel,
                    IsSent = r.IsSent,
                    SentAt = r.SentAt
                }).ToList(),
                Recurrence = entity.Recurrence is null
                    ? null
                    : new RecurrenceDto
                    {
                        Type = entity.Recurrence.Type,
                        Interval = entity.Recurrence.Interval,
                        WeekDays = ParseWeekDays(entity.Recurrence.WeekDays),
                        EndDate = entity.Recurrence.EndDate,
                        OccurrenceCount = entity.Recurrence.OccurrenceCount
                    }
            };

            return Result<EventDetailDto>.Success(dto);
        }
        catch (Exception ex)
        {
            Log.Error($"EventGetById: {ex.Message}", ex);
            return Error.ServerError;
        }
    }

    private static List<int>? ParseWeekDays(string? weekDays)
    {
        if (string.IsNullOrWhiteSpace(weekDays))
            return null;

        return weekDays
            .Split(',', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries)
            .Select(x => int.TryParse(x, out var d) ? d : -1)
            .Where(x => x >= 0)
            .ToList();
    }
}

namespace Application.Features.Query;

/// <summary>Query for calendar range items (events + optional task deadlines).</summary>
/// <param name="From">Range start (UTC).</param>
/// <param name="To">Range end (UTC).</param>
/// <param name="CalendarIds">Optional filter calendar ids.</param>
/// <param name="IncludeTaskDeadlines">Whether to include task due dates.</param>
public record CalendarRangeQuery(
    DateTime From,
    DateTime To,
    List<int>? CalendarIds,
    bool IncludeTaskDeadlines = true) : IRequest<Result<List<CalendarRangeItemDto>>>;

using Application.DTOs.Calendar;
using Application.Errors;
using Application.Features.App.Calendar;
using Application.Services;

namespace Application.Features.Query;

/// <summary>Handles calendar range query with recurrence expansion.</summary>
public class CalendarRangeQueryHandler(
    IApplicationDbContext context,
    ICurrentUserService currentUser)
    : IRequestHandler<CalendarRangeQuery, Result<List<CalendarRangeItemDto>>>
{
    private static readonly TimeSpan MaxRange = TimeSpan.FromDays(92);

    /// <inheritdoc />
    public async Task<Result<List<CalendarRangeItemDto>>> Handle(
        CalendarRangeQuery request,
        CancellationToken cancellationToken)
    {
        try
        {
            if (request.To <= request.From)
                return EventErrors.InvalidRange;

            if (request.To - request.From > MaxRange)
                return EventErrors.RangeTooLarge;

            var userId = currentUser.UserId();
            var positionIds = await CalendarAccessHelper.GetUserPositionIdsAsync(
                context, userId, cancellationToken);

            var visibleCalendarQuery = context.Calendars.AsNoTracking()
                .Where(x =>
                    (x.Type == CalendarType.Personal && x.OwnerUserId == userId)
                    || (x.Type == CalendarType.Unit
                        && x.OrgPositionId.HasValue
                        && positionIds.Contains(x.OrgPositionId.Value))
                    || x.Type == CalendarType.Organization);

            if (request.CalendarIds is { Count: > 0 })
                visibleCalendarQuery = visibleCalendarQuery.Where(x => request.CalendarIds.Contains(x.Id));

            var calendars = await visibleCalendarQuery.ToListAsync(cancellationToken);
            var calendarMap = calendars.ToDictionary(x => x.Id);

            var calendarIds = calendars.Select(x => x.Id).ToList();
            var items = new List<CalendarRangeItemDto>();

            if (calendarIds.Count > 0)
            {
                var events = await context.CalendarEvents
                    .AsNoTracking()
                    .Include(x => x.Recurrence)
                    .Include(x => x.Exceptions)
                    .Where(x => calendarIds.Contains(x.CalendarId))
                    .Where(x => x.Status != EventStatus.Cancelled)
                    .ToListAsync(cancellationToken);

                foreach (var evt in events)
                {
                    if (!calendarMap.TryGetValue(evt.CalendarId, out var cal))
                        continue;

                    foreach (var occurrence in RecurrenceExpander.Expand(evt, request.From, request.To))
                    {
                        items.Add(new CalendarRangeItemDto
                        {
                            Kind = RangeItemKind.Event,
                            EventId = evt.Id,
                            Title = evt.Title,
                            Type = evt.Type,
                            StartAt = occurrence.StartAt,
                            EndAt = occurrence.EndAt,
                            IsAllDay = evt.IsAllDay,
                            Status = evt.Status,
                            Color = cal.Color,
                            OccurrenceDate = occurrence.OccurrenceDate
                        });
                    }
                }
            }

            if (request.IncludeTaskDeadlines)
            {
                var tasks = await context.TaskItems
                    .AsNoTracking()
                    .Where(x => x.AssignedToUserId == userId || x.CreatedByUserId == userId)
                    .Where(x => x.DueDate >= request.From && x.DueDate <= request.To)
                    .Where(x => x.Status != TaskStatus.Completed && x.Status != TaskStatus.Cancelled)
                    .ToListAsync(cancellationToken);

                foreach (var task in tasks)
                {
                    items.Add(new CalendarRangeItemDto
                    {
                        Kind = RangeItemKind.TaskDeadline,
                        TaskId = task.Id,
                        Title = $"Due: {task.Title}",
                        Type = EventType.Deadline,
                        StartAt = task.DueDate,
                        EndAt = task.DueDate,
                        IsAllDay = false,
                        Status = null,
                        Color = CalendarAccessHelper.GetEventTypeColor(EventType.Deadline)
                    });
                }
            }

            return Result<List<CalendarRangeItemDto>>.Success(
                items.OrderBy(x => x.StartAt).ToList());
        }
        catch (Exception ex)
        {
            Log.Error($"CalendarRange: {ex.Message}", ex);
            return Error.ServerError;
        }
    }
}

using Application.ResultPattern;

namespace Api.Extentions;

/// <summary>
/// Maps <see cref="Result"/> failures to RFC 7807 problem responses with correct status codes.
/// </summary>
public static class CalendarProblemResults
{
    /// <summary>
    /// Returns 200 OK on success or a problem response mapped from <see cref="ErrorType"/>.
    /// </summary>
    public static IResult FromResult(Result result)
    {
        if (result.IsSuccess)
            return Results.Ok(true);

        return FromError(result.Error!);
    }

    /// <summary>
    /// Returns 200 OK with value on success or a problem response on failure.
    /// </summary>
    public static IResult FromResult<T>(Result<T> result)
    {
        if (result.IsSuccess)
            return Results.Ok(result.Value);

        return FromError(result.Error!);
    }

    private static IResult FromError(Error error)
    {
        var status = error.ErrorType switch
        {
            ErrorType.NotFound => StatusCodes.Status404NotFound,
            ErrorType.AccessForbidden => StatusCodes.Status403Forbidden,
            ErrorType.Conflict => StatusCodes.Status409Conflict,
            _ => StatusCodes.Status400BadRequest
        };

        return Results.Problem(error.Description, statusCode: status);
    }
}

using Api.Constants;
using Api.Extentions;
using Application.DTOs.Calendar;
