        {
            var res = await sender.Send(new CalendarListQuery(), cancellationToken);
            return CalendarProblemResults.FromResult(res);
        })
        .WithName("CalendarList")
        .Produces<List<CalendarDto>>(StatusCodes.Status200OK)
        .ProducesProblem(StatusCodes.Status400BadRequest)
        .WithSummary("A1 — List visible calendars")
        .WithDescription("Lists calendars visible to the current user; auto-creates default personal calendar if missing.")
        .RequireRateLimiting(RateLimitConst.RateFix)
        .RequireAuthorization();

        app.MapPost("/Calendar", async ([FromBody] CalendarCreateDto request, ISender sender, CancellationToken cancellationToken) =>
        {
            var res = await sender.Send(new CalendarCreateCommand(request), cancellationToken);
            return CalendarProblemResults.FromResult(res);
        })
        .WithName("CalendarCreate")
        .Produces<int>(StatusCodes.Status200OK)
        .ProducesProblem(StatusCodes.Status400BadRequest)
        .ProducesProblem(StatusCodes.Status403Forbidden)
        .ProducesProblem(StatusCodes.Status404NotFound)
        .WithSummary("A2 — Create calendar")
        .RequireRateLimiting(RateLimitConst.RateFix)
        .RequireAuthorization();

        app.MapPut("/Calendar", async ([FromBody] CalendarEditDto request, ISender sender, CancellationToken cancellationToken) =>
        {
            var res = await sender.Send(new CalendarUpdateCommand(request), cancellationToken);
            return CalendarProblemResults.FromResult(res);
        })
        .WithName("CalendarUpdate")
        .Produces<bool>(StatusCodes.Status200OK)
