        app.MapGet("/Calendar/Range", async (
            DateTime from,
            DateTime to,
            string? calendarIds,
            bool? includeTaskDeadlines,
            ISender sender,
            CancellationToken cancellationToken) =>
        {
            List<int>? ids = null;
            if (!string.IsNullOrWhiteSpace(calendarIds))
