$ErrorActionPreference = 'Stop'
$jsonPath = 'd:\Elay_Backend-master\.cursor\calendar-integration-collection.json'
$genPath = 'd:\Elay_Backend-master\.cursor\gen-calendar-integration-collection.ps1'

