using Application.Data;
using Application.Services;
using Application.Services.Interface;
using Domain.Models;

namespace Application.Features.CalendarSupport;

/// <summary>
/// Sends in-app and SMS notifications for calendar event invitations.
/// </summary>
public static class CalendarInviteNotificationHelper
{
    /// <summary>
    /// Notifies newly invited users via notification center (push/in-app) and SMS.
    /// </summary>
    /// <param name="context">Database context.</param>
    /// <param name="dateTime">Clock service.</param>
    /// <param name="smsService">SMS delivery service.</param>
    /// <param name="eventId">The calendar event id.</param>
    /// <param name="eventTitle">The event title.</param>
    /// <param name="inviterName">The inviter display name.</param>
    /// <param name="inviteeUserIds">User ids that were newly invited.</param>
    /// <param name="cancellationToken">Cancellation token.</param>
    public static async Task NotifyInviteesAsync(
        IApplicationDbContext context,
        IDateTimeService dateTime,
        ISmsService smsService,
        int eventId,
        string eventTitle,
        string inviterName,
        IReadOnlyList<int> inviteeUserIds,
        CancellationToken cancellationToken)
    {
        if (inviteeUserIds.Count == 0)
            return;

        var users = await context.AppUsers
            .AsNoTracking()
            .Where(x => inviteeUserIds.Contains(x.Id))
            .Select(x => new { x.Id, x.PhoneNumber })
            .ToListAsync(cancellationToken);

        foreach (var userId in inviteeUserIds)
        {
            var notification = NotificationCenter.CalendarInvite(
                eventId,
                eventTitle,
                inviterName,
                userId);

            var existing = await context.NotificationCenters
                .Where(x => x.DataId == eventId)
                .Where(x => x.Type == NotificationType.Calendar)
                .Where(x => x.UserId == userId)
                .FirstOrDefaultAsync(cancellationToken);

            if (existing is not null)
            {
                existing.Items.Add(notification.Items.First());
                existing.LastDateTime = dateTime.Now;
            }
            else
            {
                notification.LastDateTime = dateTime.Now;
                context.NotificationCenters.Add(notification);
            }

            var phone = users.FirstOrDefault(x => x.Id == userId)?.PhoneNumber;
            if (!string.IsNullOrWhiteSpace(phone))
            {
                var smsBody =
                    $"دعوت به رویداد «{eventTitle}» از طرف {inviterName}. لطفاً در اپلیکیشن پاسخ دهید.";
                await smsService.SendAsync(phone, smsBody, cancellationToken);
            }
        }
    }
}

using Application.DTOs.Calendar;
using FluentValidation;

namespace Application.Features.Command;

/// <summary>Command to add participants to a calendar event.</summary>
/// <param name="Model">Participant add input.</param>
public record EventAddParticipantsCommand(EventAddParticipantsDto Model) : IRequest<Result<bool>>;

/// <summary>Validates participant add input.</summary>
public class EventAddParticipantsCommandValidator : AbstractValidator<EventAddParticipantsCommand>
{
    public EventAddParticipantsCommandValidator()
    {
        RuleFor(x => x.Model.EventId).GreaterThan(0);
        RuleFor(x => x.Model.UserIds)
            .NotEmpty().WithMessage("حداقل یک کاربر الزامی است");
