/// <summary>Command to remove a participant from a calendar event.</summary>
/// <param name="EventId">The event identifier.</param>
/// <param name="UserId">The participant user identifier.</param>
public record EventRemoveParticipantCommand(int EventId, int UserId) : IRequest<Result<bool>>;

using Application.Errors;
using Application.Features.CalendarSupport;
using Application.Services;
using Domain.Models;

namespace Application.Features.Command;

/// <summary>Handles removing a participant from a calendar event (D2).</summary>
public class EventRemoveParticipantCommandHandler(
    IApplicationDbContext context,
    ICurrentUserService currentUser,
    IDateTimeService dateTime)
    : IRequestHandler<EventRemoveParticipantCommand, Result<bool>>
{
    /// <inheritdoc />
    public async Task<Result<bool>> Handle(
        EventRemoveParticipantCommand request,
        CancellationToken cancellationToken)
    {
        try
        {
            var userId = currentUser.UserId();

            var entity = await context.CalendarEvents
                .Include(x => x.Calendar)
                .Include(x => x.Participants)
                .FirstOrDefaultAsync(x => x.Id == request.EventId, cancellationToken);

            if (entity is null)
                return EventErrors.ParticipantNotFound;

            var participant = entity.Participants
                .FirstOrDefault(x => x.UserId == request.UserId && !x.IsDeleted);

            if (participant is null)
                return EventErrors.ParticipantNotFound;

            var positionIds = await CalendarAccessHelper.GetUserPositionIdsAsync(
                context, userId, cancellationToken);

            if (!await CalendarAccessHelper.CanEditEventAsync(
                    entity, userId, currentUser, positionIds, cancellationToken))
                return EventErrors.ParticipantRemoveForbidden;

            participant.IsDeleted = true;
            participant.DeleteDate = dateTime.Now;

            await context.SaveChangesAsync(cancellationToken);
            return Result<bool>.Success(true);
        }
        catch (Exception ex)
        {
            Log.Error($"EventRemoveParticipant: {ex.Message}", ex);
            return Error.ServerError;
        }
    }
}

using Application.DTOs.Calendar;
using FluentValidation;

namespace Application.Features.Command;

/// <summary>Command for an invitee to respond to a calendar event invitation.</summary>
/// <param name="Model">RSVP input.</param>
public record EventRespondCommand(EventRespondDto Model) : IRequest<Result<bool>>;

/// <summary>Validates RSVP input.</summary>
public class EventRespondCommandValidator : AbstractValidator<EventRespondCommand>
{
    public EventRespondCommandValidator()
    {
        RuleFor(x => x.Model.EventId).GreaterThan(0);
        RuleFor(x => x.Model.Response).NotEmpty();
    }
}

using Application.Errors;
using Application.Services;

namespace Application.Features.Command;

/// <summary>Handles invitee RSVP responses (D3).</summary>
public class EventRespondCommandHandler(
    IApplicationDbContext context,
    ICurrentUserService currentUser)
    : IRequestHandler<EventRespondCommand, Result<bool>>
{
    /// <inheritdoc />
    public async Task<Result<bool>> Handle(
        EventRespondCommand request,
        CancellationToken cancellationToken)
    {
        try
        {
            var model = request.Model;
            var userId = currentUser.UserId();

            if (!TryParseResponse(model.Response, out var response))
                return EventErrors.InvalidResponse;

            var entity = await context.CalendarEvents
                .Include(x => x.Participants)
                .FirstOrDefaultAsync(x => x.Id == model.EventId, cancellationToken);

            if (entity is null)
                return EventErrors.NotFound;

            var participant = entity.Participants
                .FirstOrDefault(x => x.UserId == userId && !x.IsDeleted);

            if (participant is null)
                return EventErrors.NotInvited;

            participant.Response = response;

            await context.SaveChangesAsync(cancellationToken);
            return Result<bool>.Success(true);
        }
        catch (Exception ex)
        {
            Log.Error($"EventRespond: {ex.Message}", ex);
            return Error.ServerError;
        }
    }

    private static bool TryParseResponse(string value, out ParticipantResponse response)
    {
        response = default;
        if (string.IsNullOrWhiteSpace(value))
            return false;

        return value.Trim() switch
        {
            "Accepted" => Assign(ParticipantResponse.Accepted, out response),
            "Declined" => Assign(ParticipantResponse.Declined, out response),
            "Maybe" => Assign(ParticipantResponse.Maybe, out response),
            _ => false
        };
    }

    private static bool Assign(ParticipantResponse value, out ParticipantResponse result)
    {
        result = value;
        return true;
    }
}

using Application.DTOs.Calendar;

namespace Application.Features.Query;

/// <summary>Query to list participants for a calendar event.</summary>
/// <param name="EventId">The event identifier.</param>
public record EventParticipantsQuery(int EventId) : IRequest<Result<List<ParticipantDto>>>;

using Application.DTOs.Calendar;
using Application.Errors;
using Application.Features.CalendarSupport;
using Application.Services;

namespace Application.Features.Query;

/// <summary>Handles listing event participants (D4).</summary>
public class EventParticipantsQueryHandler(
    IApplicationDbContext context,
    ICurrentUserService currentUser)
    : IRequestHandler<EventParticipantsQuery, Result<List<ParticipantDto>>>
{
    /// <inheritdoc />
    public async Task<Result<List<ParticipantDto>>> Handle(
        EventParticipantsQuery request,
        CancellationToken cancellationToken)
    {
        try
        {
            var userId = currentUser.UserId();

            var entity = await context.CalendarEvents
                .AsNoTracking()
                .Include(x => x.Participants).ThenInclude(x => x.User)
                .FirstOrDefaultAsync(x => x.Id == request.EventId, cancellationToken);

            if (entity is null)
                return EventErrors.NotFound;

            if (!CalendarAccessHelper.CanViewEventParticipants(entity, userId))
                return EventErrors.ParticipantsViewForbidden;

            var dtos = entity.Participants
                .Where(x => !x.IsDeleted)
                .Select(p => new ParticipantDto
                {
                    UserId = p.UserId,
                    FullName = p.User.Name,
                    Response = p.Response
                })
                .ToList();

            return Result<List<ParticipantDto>>.Success(dtos);
        }
        catch (Exception ex)
        {
            Log.Error($"EventParticipants: {ex.Message}", ex);
            return Error.ServerError;
        }
    }
}

