using Application.Data;
using Domain.Models.Organization;

namespace Application.Features.CalendarSupport;

/// <summary>
/// Resolves subordinate users from the organizational position tree.
/// </summary>
public static class CalendarSubordinateHelper
{
    /// <summary>
    /// Returns distinct subordinate users for the manager (ManagerId links + ParentId descendants).
    /// </summary>
    /// <param name="context">Database context.</param>
    /// <param name="managerUserId">Current manager user id.</param>
    /// <param name="managerPositionIds">Org position ids assigned to the manager.</param>
    /// <param name="cancellationToken">Cancellation token.</param>
    /// <returns>Subordinate user id and display name pairs.</returns>
    public static async Task<List<(int UserId, string FullName)>> GetSubordinateUsersAsync(
        IApplicationDbContext context,
        int managerUserId,
        HashSet<int> managerPositionIds,
        CancellationToken cancellationToken)
    {
        if (managerPositionIds.Count == 0)
            return [];

        var positions = await context.OrgPositions
            .AsNoTracking()
            .Select(x => new { x.Id, x.ParentId, x.ManagerId })
            .ToListAsync(cancellationToken);

        var subordinatePositionIds = new HashSet<int>();

        foreach (var position in positions)
        {
            if (position.ManagerId.HasValue
                && managerPositionIds.Contains(position.ManagerId.Value))
            {
                subordinatePositionIds.Add(position.Id);
            }
        }

        void AddChildren(int parentId)
        {
            foreach (var child in positions.Where(x => x.ParentId == parentId))
            {
                if (subordinatePositionIds.Add(child.Id))
                    AddChildren(child.Id);
            }
        }

        foreach (var myId in managerPositionIds)
            AddChildren(myId);

        foreach (var id in subordinatePositionIds.ToList())
            AddChildren(id);

        if (subordinatePositionIds.Count == 0)
            return [];

        var users = await context.PositionUsers
            .AsNoTracking()
            .Where(x => subordinatePositionIds.Contains(x.OrgPositionId))
            .Where(x => x.UserId != managerUserId)
            .Select(x => new { x.UserId, x.User.Name })
            .ToListAsync(cancellationToken);

        return users
            .GroupBy(x => x.UserId)
            .Select(g => (g.Key, g.First().Name))
            .OrderBy(x => x.Name)
            .ToList();
    }
}

using Application.DTOs.Calendar;
using Domain.Models;

namespace Application.Features.CalendarSupport;

/// <summary>
/// Builds busy slots and manager-view items from confirmed calendar events.
/// </summary>
public static class CalendarBusyHelper
{
    /// <summary>
    /// Returns true when the user is considered busy on the event.
    /// </summary>
    public static bool IsUserBusyOnEvent(CalendarEvent evt, int userId)
    {
        if (evt.Status != EventStatus.Confirmed)
            return false;

        if (evt.CreatedByUserId == userId)
            return true;

        return evt.Participants.Any(p =>
            p.UserId == userId
            && !p.IsDeleted
            && p.Response != ParticipantResponse.Declined);
    }

    /// <summary>
    /// Expands confirmed event occurrences for a user into busy slots.
    /// </summary>
    public static IEnumerable<BusySlotDto> GetBusySlots(
        CalendarEvent evt,
        int userId,
        DateTime from,
        DateTime to)
    {
        if (!IsUserBusyOnEvent(evt, userId))
            yield break;

        foreach (var occurrence in RecurrenceExpander.Expand(evt, from, to))
        {
            yield return new BusySlotDto
            {
                StartAt = occurrence.StartAt,
                EndAt = occurrence.EndAt
            };
        }
    }

    /// <summary>
    /// Expands confirmed event occurrences into subordinate range items.
    /// </summary>
    public static IEnumerable<SubordinateRangeItemDto> GetSubordinateItems(
        CalendarEvent evt,
        int userId,
        string userFullName,
        DateTime from,
        DateTime to)
    {
        if (!IsUserBusyOnEvent(evt, userId))
            yield break;

        var busyOnly = evt.IsPersonal;

        foreach (var occurrence in RecurrenceExpander.Expand(evt, from, to))
        {
            yield return new SubordinateRangeItemDto
            {
                UserId = userId,
                UserFullName = userFullName,
                StartAt = occurrence.StartAt,
                EndAt = occurrence.EndAt,
                Title = busyOnly ? null : evt.Title,
                IsBusyOnly = busyOnly
            };
        }
    }
}

namespace Application.Features.Query;

/// <summary>Query Free/Busy slots for one or more users.</summary>
/// <param name="UserIds">Target user identifiers.</param>
/// <param name="From">Range start (UTC).</param>
/// <param name="To">Range end (UTC).</param>
public record CalendarFreeBusyQuery(
    List<int> UserIds,
    DateTime From,
    DateTime To) : IRequest<Result<List<FreeBusyDto>>>;

using Application.DTOs.Calendar;
using Application.Errors;
using Application.Features.CalendarSupport;

namespace Application.Features.Query;

/// <summary>Handles Free/Busy queries (C1).</summary>
public class CalendarFreeBusyQueryHandler(IApplicationDbContext context)
    : IRequestHandler<CalendarFreeBusyQuery, Result<List<FreeBusyDto>>>
{
    /// <inheritdoc />
    public async Task<Result<List<FreeBusyDto>>> Handle(
        CalendarFreeBusyQuery request,
        CancellationToken cancellationToken)
    {
        try
        {
            if (request.UserIds is null || request.UserIds.Count == 0)
                return EventErrors.AtLeastOneUserRequired;

            var distinctIds = request.UserIds.Distinct().ToList();

            var rangeError = CalendarAccessHelper.ValidateTimeRange(request.From, request.To);
            if (rangeError is not null)
                return rangeError;

            var existingCount = await context.AppUsers
                .AsNoTracking()
                .CountAsync(x => distinctIds.Contains(x.Id), cancellationToken);

            if (existingCount != distinctIds.Count)
                return EventErrors.InvalidUserInList;

            var events = await context.CalendarEvents
                .AsNoTracking()
                .Include(x => x.Recurrence)
                .Include(x => x.Exceptions)
                .Include(x => x.Participants)
                .Where(x => x.Status == EventStatus.Confirmed)
                .Where(x =>
                    distinctIds.Contains(x.CreatedByUserId)
                    || x.Participants.Any(p =>
                        distinctIds.Contains(p.UserId)
                        && p.Response != ParticipantResponse.Declined))
                .ToListAsync(cancellationToken);

            var result = new List<FreeBusyDto>(distinctIds.Count);

            foreach (var userId in distinctIds)
            {
                var slots = events
                    .SelectMany(evt => CalendarBusyHelper.GetBusySlots(
                        evt, userId, request.From, request.To))
                    .OrderBy(x => x.StartAt)
                    .ToList();

                result.Add(new FreeBusyDto
                {
                    UserId = userId,
                    BusySlots = slots
                });
            }

            return Result<List<FreeBusyDto>>.Success(result);
        }
        catch (Exception ex)
        {
            Log.Error($"CalendarFreeBusy: {ex.Message}", ex);
            return Error.ServerError;
        }
    }
}

namespace Application.Features.Query;

/// <summary>Query subordinate events for the manager view.</summary>
/// <param name="From">Range start (UTC).</param>
/// <param name="To">Range end (UTC).</param>
public record CalendarSubordinatesRangeQuery(
    DateTime From,
    DateTime To) : IRequest<Result<List<SubordinateRangeItemDto>>>;

using Application.DTOs.Calendar;
using Application.Errors;
using Application.Features.CalendarSupport;
using Application.Services;

namespace Application.Features.Query;

/// <summary>Handles subordinate calendar range queries (B6).</summary>
public class CalendarSubordinatesRangeQueryHandler(
    IApplicationDbContext context,
    ICurrentUserService currentUser)
    : IRequestHandler<CalendarSubordinatesRangeQuery, Result<List<SubordinateRangeItemDto>>>
{
    /// <inheritdoc />
    public async Task<Result<List<SubordinateRangeItemDto>>> Handle(
        CalendarSubordinatesRangeQuery request,
        CancellationToken cancellationToken)
    {
        try
        {
            var rangeError = CalendarAccessHelper.ValidateTimeRange(request.From, request.To);
            if (rangeError is not null)
                return rangeError;

            var managerUserId = currentUser.UserId();
            var managerPositionIds = await CalendarAccessHelper.GetUserPositionIdsAsync(
                context, managerUserId, cancellationToken);

            var subordinates = await CalendarSubordinateHelper.GetSubordinateUsersAsync(
                context,
                managerUserId,
                managerPositionIds,
                cancellationToken);

            if (subordinates.Count == 0)
                return Result<List<SubordinateRangeItemDto>>.Success([]);

            var userIds = subordinates.Select(x => x.UserId).ToList();
            var nameById = subordinates.ToDictionary(x => x.UserId, x => x.FullName);

            var events = await context.CalendarEvents
                .AsNoTracking()
                .Include(x => x.Recurrence)
                .Include(x => x.Exceptions)
                .Include(x => x.Participants)
                .Where(x => x.Status == EventStatus.Confirmed)
                .Where(x =>
                    userIds.Contains(x.CreatedByUserId)
                    || x.Participants.Any(p =>
                        userIds.Contains(p.UserId)
                        && p.Response != ParticipantResponse.Declined))
                .ToListAsync(cancellationToken);

            var items = new List<SubordinateRangeItemDto>();

            foreach (var userId in userIds)
            {
                var fullName = nameById[userId];
                foreach (var evt in events)
                {
                    items.AddRange(
                        CalendarBusyHelper.GetSubordinateItems(
                            evt, userId, fullName, request.From, request.To));
                }
            }

            return Result<List<SubordinateRangeItemDto>>.Success(
                items.OrderBy(x => x.StartAt).ThenBy(x => x.UserId).ToList());
        }
        catch (Exception ex)
        {
            Log.Error($"CalendarSubordinatesRange: {ex.Message}", ex);
            return Error.ServerError;
        }
    }
}

