namespace Domain.Models;

/// <summary>
/// Represents an approval-based meeting request between two users.
/// </summary>
public class MeetingRequest : Entity<int>
{
    /// <summary>Gets or sets the requester user id.</summary>
    public int RequesterUserId { get; set; }

    /// <summary>Gets or sets the requester user.</summary>
    public AppUser RequesterUser { get; set; } = null!;

    /// <summary>Gets or sets the target user id.</summary>
    public int TargetUserId { get; set; }

    /// <summary>Gets or sets the target user.</summary>
    public AppUser TargetUser { get; set; } = null!;

    /// <summary>Gets or sets the meeting title.</summary>
    public string Title { get; set; } = string.Empty;

    /// <summary>Gets or sets the optional description.</summary>
    public string? Description { get; set; }

    /// <summary>Gets or sets the optional location.</summary>
    public string? Location { get; set; }

    /// <summary>Gets or sets the proposed start time (UTC).</summary>
    public DateTime StartAt { get; set; }

    /// <summary>Gets or sets the proposed end time (UTC).</summary>
    public DateTime EndAt { get; set; }

    /// <summary>Gets or sets the request status.</summary>
    public MeetingRequestStatus Status { get; set; } = MeetingRequestStatus.Pending;

    /// <summary>Gets or sets the optional rejection reason.</summary>
    public string? Reason { get; set; }

    /// <summary>Gets or sets the created event id after approval.</summary>
    public int? ResultEventId { get; set; }

    /// <summary>Gets or sets the resulting calendar event.</summary>
    public CalendarEvent? ResultEvent { get; set; }
}

namespace Infrastructure.Data.Configuration.CalendarEntities;

public class MeetingRequestConfiguration : IEntityTypeConfiguration<MeetingRequest>
{
    public void Configure(EntityTypeBuilder<MeetingRequest> builder)
    {
        builder.Property(x => x.Title)
            .IsRequired()
            .HasMaxLength(200);

        builder.Property(x => x.Description)
            .HasMaxLength(2048);

        builder.Property(x => x.Location)
            .HasMaxLength(500);

        builder.Property(x => x.Reason)
            .HasMaxLength(1000);

        builder.HasOne(x => x.RequesterUser)
            .WithMany()
            .HasForeignKey(x => x.RequesterUserId)
            .OnDelete(DeleteBehavior.Restrict);

        builder.HasOne(x => x.TargetUser)
            .WithMany()
            .HasForeignKey(x => x.TargetUserId)
            .OnDelete(DeleteBehavior.Restrict);

        builder.HasOne(x => x.ResultEvent)
            .WithMany()
            .HasForeignKey(x => x.ResultEventId)
            .OnDelete(DeleteBehavior.Restrict);

        builder.HasIndex(x => new { x.TargetUserId, x.Status });
        builder.HasIndex(x => new { x.RequesterUserId, x.Status });
    }
}

using Application.Data;
