using Application.Services.Interface;
using Domain.Models;

namespace Application.Features.CalendarSupport;

/// <summary>
/// Notifies users about meeting-request lifecycle (SMS first, then in-app center).
/// </summary>
public static class MeetingRequestNotificationHelper
{
    /// <summary>
    /// Sends SMS (priority) and writes an in-app notification center item.
    /// </summary>
    public static async Task NotifyAsync(
        IApplicationDbContext context,
        IDateTimeService dateTime,
        ISmsService smsService,
        int? dataId,
        int recipientUserId,
        string subject,
        string content,
        string smsBody,
        CancellationToken cancellationToken)
    {
        var phone = await context.AppUsers
            .AsNoTracking()
            .Where(x => x.Id == recipientUserId)
            .Select(x => x.PhoneNumber)
            .FirstOrDefaultAsync(cancellationToken);

        if (!string.IsNullOrWhiteSpace(phone))
            await smsService.SendAsync(phone, smsBody, cancellationToken);

        var notification = new NotificationCenter(
            dataId,
            subject,
            content,
            recipientUserId,
            NotificationType.Calendar);

        var existing = await context.NotificationCenters
            .Where(x => x.DataId == dataId)
            .Where(x => x.Type == NotificationType.Calendar)
            .Where(x => x.UserId == recipientUserId)
            .FirstOrDefaultAsync(cancellationToken);

        if (existing is not null)
        {
            existing.Items.Add(notification.Items.First());
            existing.LastDateTime = dateTime.Now;
        }
        else
        {
            notification.LastDateTime = dateTime.Now;
            context.NotificationCenters.Add(notification);
        }
    }
}

