/// <summary>Validates meeting request create input.</summary>
public class MeetingRequestCreateCommandValidator : AbstractValidator<MeetingRequestCreateCommand>
{
    public MeetingRequestCreateCommandValidator()
    {
        RuleFor(x => x.Model.TargetUserId).GreaterThan(0);
        RuleFor(x => x.Model.Title)
            .NotEmpty().WithMessage("عنوان الزامی است")
            .MinimumLength(2).WithMessage("عنوان باید حداقل ۲ کاراکتر باشد")
            .MaximumLength(200);
