using Application.DTOs.Calendar;
using Application.Errors;
using Application.Features.CalendarSupport;
using Application.Services;
using Application.Services.Interface;
using Domain.Models;

namespace Application.Features.Command;

/// <summary>Handles creating a meeting request (E1).</summary>
public class MeetingRequestCreateCommandHandler(
    IApplicationDbContext context,
    ICurrentUserService currentUser,
    IDateTimeService dateTime,
    ISmsService smsService)
    : IRequestHandler<MeetingRequestCreateCommand, Result<int>>
{
    /// <inheritdoc />
    public async Task<Result<int>> Handle(
        MeetingRequestCreateCommand request,
        CancellationToken cancellationToken)
    {
        try
        {
            var model = request.Model;
            var requesterId = currentUser.UserId();

            if (string.IsNullOrWhiteSpace(model.Title))
                return MeetingRequestErrors.TitleRequired;

            if (model.Title.Trim().Length < 2)
                return MeetingRequestErrors.TitleTooShort;

            if (model.EndAt <= model.StartAt)
                return MeetingRequestErrors.InvalidTimeRange;

            if (model.TargetUserId == requesterId)
                return MeetingRequestErrors.CannotRequestWithSelf;

            var target = await context.AppUsers
                .AsNoTracking()
                .Where(x => x.Id == model.TargetUserId)
                .Select(x => new { x.Id, x.Name })
                .FirstOrDefaultAsync(cancellationToken);

            if (target is null)
                return MeetingRequestErrors.TargetUserNotFound;

            var conflictName = await EventConflictHelper.FindConflictUserNameAsync(
                context,
                [model.TargetUserId],
                model.StartAt,
                model.EndAt,
                null,
                cancellationToken);

            if (conflictName is not null)
                return MeetingRequestErrors.Conflict(conflictName);

            var entity = new MeetingRequest
            {
                RequesterUserId = requesterId,
                TargetUserId = model.TargetUserId,
                Title = model.Title.Trim(),
                Description = model.Description,
                Location = model.Location,
                StartAt = model.StartAt,
                EndAt = model.EndAt,
                Status = MeetingRequestStatus.Pending
            };

            await context.MeetingRequests.AddAsync(entity, cancellationToken);
            await context.SaveChangesAsync(cancellationToken);

            var requesterName = await context.AppUsers
                .AsNoTracking()
                .Where(x => x.Id == requesterId)
                .Select(x => x.Name)
                .FirstOrDefaultAsync(cancellationToken) ?? "کاربر";

            await MeetingRequestNotificationHelper.NotifyAsync(
                context,
                dateTime,
                smsService,
                entity.Id,
                model.TargetUserId,
                $"درخواست جلسه: {entity.Title}",
                $"از طرف {requesterName} برای شما ثبت شد.",
                $"درخواست جلسه «{entity.Title}» از {requesterName}. لطفاً در اپلیکیشن تایید یا رد کنید.",
                cancellationToken);

            await context.SaveChangesAsync(cancellationToken);

            return Result<int>.Success(entity.Id);
        }
        catch (Exception ex)
        {
            Log.Error($"MeetingRequestCreate: {ex.Message}", ex);
            return Error.ServerError;
        }
    }
}

