/// <summary>Command to approve a meeting request.</summary>
/// <param name="Model">Approve input.</param>
public record MeetingRequestApproveCommand(MeetingRequestApproveDto Model) : IRequest<Result<int>>;

using Application.DTOs.Calendar;
using Application.Errors;
using Application.Features.CalendarSupport;
using Application.Services;
using Application.Services.Interface;
using Domain.Models;

namespace Application.Features.Command;

/// <summary>Handles approving a meeting request (E2).</summary>
public class MeetingRequestApproveCommandHandler(
    IApplicationDbContext context,
    ICurrentUserService currentUser,
    IDateTimeService dateTime,
    ISmsService smsService)
    : IRequestHandler<MeetingRequestApproveCommand, Result<int>>
{
    /// <inheritdoc />
    public async Task<Result<int>> Handle(
        MeetingRequestApproveCommand request,
        CancellationToken cancellationToken)
    {
        try
        {
            var userId = currentUser.UserId();

            var entity = await context.MeetingRequests
                .Include(x => x.RequesterUser)
                .FirstOrDefaultAsync(x => x.Id == request.Model.RequestId, cancellationToken);

            if (entity is null)
                return MeetingRequestErrors.NotFound;

            if (entity.TargetUserId != userId)
                return MeetingRequestErrors.OnlyTargetCanApprove;

            if (entity.Status != MeetingRequestStatus.Pending)
                return MeetingRequestErrors.AlreadyProcessed;

            var conflictIds = new[] { entity.RequesterUserId, entity.TargetUserId };
            var conflictName = await EventConflictHelper.FindConflictUserNameAsync(
                context,
                conflictIds,
                entity.StartAt,
                entity.EndAt,
                null,
                cancellationToken);

            if (conflictName is not null)
                return MeetingRequestErrors.Conflict(conflictName);

            var calendar = await context.Calendars
                .FirstOrDefaultAsync(
                    x => x.Type == CalendarType.Personal
                         && x.OwnerUserId == entity.RequesterUserId
                         && x.IsDefault,
                    cancellationToken);

            if (calendar is null)
            {
                calendar = Calendar.CreateDefaultPersonal(entity.RequesterUserId);
                await context.Calendars.AddAsync(calendar, cancellationToken);
                await context.SaveChangesAsync(cancellationToken);
            }

            var calendarEvent = new CalendarEvent
            {
                CalendarId = calendar.Id,
                CreatedByUserId = entity.RequesterUserId,
                Title = entity.Title,
                Description = entity.Description,
                Location = entity.Location,
                Type = EventType.Meeting,
                Status = EventStatus.Confirmed,
                StartAt = entity.StartAt,
                EndAt = entity.EndAt,
                IsAllDay = false,
                IsPersonal = false,
                VisibleOnlyToParticipants = false,
                Participants =
                [
                    new CalendarParticipant
                    {
                        UserId = entity.RequesterUserId,
                        Response = ParticipantResponse.Accepted
                    },
                    new CalendarParticipant
                    {
                        UserId = entity.TargetUserId,
                        Response = ParticipantResponse.Accepted
                    }
                ],
                Reminders =
                [
                    new CalendarReminder
                    {
                        OffsetMinutes = 15,
                        Channel = ReminderChannel.Sms
                    },
                    new CalendarReminder
                    {
                        OffsetMinutes = 15,
                        Channel = ReminderChannel.InApp
                    }
                ]
            };

            await context.CalendarEvents.AddAsync(calendarEvent, cancellationToken);
            await context.SaveChangesAsync(cancellationToken);

            entity.Status = MeetingRequestStatus.Approved;
            entity.ResultEventId = calendarEvent.Id;

            var targetName = await context.AppUsers
                .AsNoTracking()
                .Where(x => x.Id == userId)
                .Select(x => x.Name)
                .FirstOrDefaultAsync(cancellationToken) ?? "کاربر";

            await MeetingRequestNotificationHelper.NotifyAsync(
                context,
                dateTime,
                smsService,
                entity.Id,
                entity.RequesterUserId,
                $"تایید درخواست جلسه: {entity.Title}",
                $"{targetName} درخواست را تایید کرد.",
                $"درخواست جلسه «{entity.Title}» توسط {targetName} تایید شد.",
                cancellationToken);

            await context.SaveChangesAsync(cancellationToken);

            return Result<int>.Success(calendarEvent.Id);
        }
        catch (Exception ex)
        {
            Log.Error($"MeetingRequestApprove: {ex.Message}", ex);
            return Error.ServerError;
        }
    }
}

