using Application.Services.Interface;

namespace Application.Features.Command;

/// <summary>Handles rejecting a meeting request (E3).</summary>
public class MeetingRequestRejectCommandHandler(
    IApplicationDbContext context,
    ICurrentUserService currentUser,
    IDateTimeService dateTime,
    ISmsService smsService)
    : IRequestHandler<MeetingRequestRejectCommand, Result<bool>>
{
    /// <inheritdoc />
    public async Task<Result<bool>> Handle(
        MeetingRequestRejectCommand request,
        CancellationToken cancellationToken)
    {
        try
        {
            var userId = currentUser.UserId();

            var entity = await context.MeetingRequests
                .FirstOrDefaultAsync(x => x.Id == request.Model.RequestId, cancellationToken);

            if (entity is null)
                return MeetingRequestErrors.NotFound;

            if (entity.TargetUserId != userId)
                return MeetingRequestErrors.OnlyTargetCanReject;

            if (entity.Status != MeetingRequestStatus.Pending)
                return MeetingRequestErrors.AlreadyProcessed;

            entity.Status = MeetingRequestStatus.Rejected;
            entity.Reason = string.IsNullOrWhiteSpace(request.Model.Reason)
                ? null
                : request.Model.Reason.Trim();

            var targetName = await context.AppUsers
                .AsNoTracking()
                .Where(x => x.Id == userId)
                .Select(x => x.Name)
                .FirstOrDefaultAsync(cancellationToken) ?? "کاربر";

            var reasonPart = string.IsNullOrWhiteSpace(entity.Reason)
                ? ""
                : $" دلیل: {entity.Reason}";

            await MeetingRequestNotificationHelper.NotifyAsync(
                context,
                dateTime,
                smsService,
                entity.Id,
                entity.RequesterUserId,
                $"رد درخواست جلسه: {entity.Title}",
                $"{targetName} درخواست را رد کرد.{reasonPart}",
                $"درخواست جلسه «{entity.Title}» توسط {targetName} رد شد.{reasonPart}",
                cancellationToken);

            await context.SaveChangesAsync(cancellationToken);
            return Result<bool>.Success(true);
        }
        catch (Exception ex)
        {
            Log.Error($"MeetingRequestReject: {ex.Message}", ex);
            return Error.ServerError;
        }
    }
}

