namespace Application.Features.Query;

/// <summary>Query pending meeting requests for the current user (as target).</summary>
/// <param name="Page">Zero-based page index.</param>
public record MeetingRequestPendingQuery(int Page = 0)
    : IRequest<Result<PaginatedResult<MeetingRequestDto>>>;

using Application.DTOs.Calendar;
using Application.Features.CalendarSupport;
using Application.Services;
using Share.Pagination;
using Share.Share;

namespace Application.Features.Query;

/// <summary>Handles pending meeting request list (E4).</summary>
public class MeetingRequestPendingQueryHandler(
    IApplicationDbContext context,
    ICurrentUserService currentUser)
    : IRequestHandler<MeetingRequestPendingQuery, Result<PaginatedResult<MeetingRequestDto>>>
{
    /// <inheritdoc />
    public async Task<Result<PaginatedResult<MeetingRequestDto>>> Handle(
        MeetingRequestPendingQuery request,
        CancellationToken cancellationToken)
    {
        try
        {
            var userId = currentUser.UserId();
            var page = request.Page < 0 ? 0 : request.Page;
            var pageSize = PaginatedResult<MeetingRequestDto>.DefaultPageSize;

            var q = context.MeetingRequests
                .AsNoTracking()
                .Include(x => x.RequesterUser)
                .Include(x => x.TargetUser)
                .Where(x => x.TargetUserId == userId)
                .Where(x => x.Status == MeetingRequestStatus.Pending)
                .OrderByDescending(x => x.CreateDate);

            var totalCount = await q.CountAsync(cancellationToken);

            var items = await q
                .Skip(page * pageSize)
                .Take(pageSize)
                .ToListAsync(cancellationToken);

            var dtos = items.Select(MeetingRequestMapper.ToDto).ToList();

            return Result<PaginatedResult<MeetingRequestDto>>.Success(
                new PaginatedResult<MeetingRequestDto>(
                    dtos, page, pageSize, dtos.Count, totalCount));
        }
        catch (Exception ex)
        {
            Log.Error($"MeetingRequestPending: {ex.Message}", ex);
            return Error.ServerError;
        }
    }
}

