namespace Api.EndPoint.Calendar;

/// <summary>Endpoints for approval-based meeting requests (Group E).</summary>
public class MeetingRequestEndPoint : ICarterModule
{
    /// <inheritdoc />
    public void AddRoutes(IEndpointRouteBuilder app)
    {
        app.MapPost("/Calendar/MeetingRequest", async (
            [FromBody] MeetingRequestCreateDto request,
            ISender sender,
            CancellationToken cancellationToken) =>
        {
            var res = await sender.Send(new MeetingRequestCreateCommand(request), cancellationToken);
            return CalendarProblemResults.FromResult(res);
        })
        .WithName("MeetingRequestCreate")
        .Produces<int>(StatusCodes.Status200OK)
        .ProducesProblem(StatusCodes.Status400BadRequest)
        .ProducesProblem(StatusCodes.Status404NotFound)
        .ProducesProblem(StatusCodes.Status409Conflict)
        .WithSummary("E1 — Create meeting request")
        .RequireRateLimiting(RateLimitConst.RateFix)
        .RequireAuthorization();

        app.MapPost("/Calendar/MeetingRequest/Approve", async (
            [FromBody] MeetingRequestApproveDto request,
            ISender sender,
            CancellationToken cancellationToken) =>
        {
            var res = await sender.Send(new MeetingRequestApproveCommand(request), cancellationToken);
            return CalendarProblemResults.FromResult(res);
        })
        .WithName("MeetingRequestApprove")
        .Produces<int>(StatusCodes.Status200OK)
        .ProducesProblem(StatusCodes.Status400BadRequest)
        .ProducesProblem(StatusCodes.Status403Forbidden)
        .ProducesProblem(StatusCodes.Status404NotFound)
        .ProducesProblem(StatusCodes.Status409Conflict)
        .WithSummary("E2 — Approve meeting request")
        .RequireRateLimiting(RateLimitConst.RateFix)
        .RequireAuthorization();

        app.MapPost("/Calendar/MeetingRequest/Reject", async (
            [FromBody] MeetingRequestRejectDto request,
            ISender sender,
            CancellationToken cancellationToken) =>
        {
            var res = await sender.Send(new MeetingRequestRejectCommand(request), cancellationToken);
            return CalendarProblemResults.FromResult(res);
        })
        .WithName("MeetingRequestReject")
        .Produces<bool>(StatusCodes.Status200OK)
        .ProducesProblem(StatusCodes.Status400BadRequest)
        .ProducesProblem(StatusCodes.Status403Forbidden)
        .ProducesProblem(StatusCodes.Status404NotFound)
        .WithSummary("E3 — Reject meeting request")
        .RequireRateLimiting(RateLimitConst.RateFix)
        .RequireAuthorization();

        app.MapGet("/Calendar/MeetingRequest/Pending", async (
            int? page,
            ISender sender,
            CancellationToken cancellationToken) =>
        {
            var res = await sender.Send(
                new MeetingRequestPendingQuery(page ?? 0),
                cancellationToken);
