/// <summary>
/// Determines whether the user can view event participant details.
/// </summary>
public static bool CanViewEventParticipants(CalendarEvent calendarEvent, int userId)
{
    if (calendarEvent.CreatedByUserId == userId)
        return true;

    if (calendarEvent.Participants.Any(x => x.UserId == userId))
        return true;

    return !calendarEvent.VisibleOnlyToParticipants;
}

/// <summary>
/// Determines whether the user can view event details and reminders (same rules as event detail).
/// </summary>
public static bool CanViewEvent(CalendarEvent calendarEvent, int userId)
{
    if (calendarEvent.CreatedByUserId == userId)
        return true;

    if (calendarEvent.Participants.Any(x => x.UserId == userId))
        return true;

    return !calendarEvent.VisibleOnlyToParticipants;
}

