namespace Application.Features.CalendarSupport;

/// <summary>
/// Finds due calendar reminders and dispatches them (single events and recurring occurrences).
/// </summary>
public class CalendarReminderDueProcessor(
    IApplicationDbContext context,
    IDateTimeService dateTime,
    ISmsService smsService)
{
    /// <summary>
    /// Processes reminders whose trigger time has passed and records dispatch to prevent duplicates.
    /// </summary>
    /// <returns>Number of reminders sent in this run.</returns>
    public async Task<int> ProcessDueAsync(CancellationToken cancellationToken)
    {
        var now = dateTime.Now;
        var rangeFrom = now.AddDays(-1);
        var rangeTo = now.AddMinutes(2);

        var reminders = await context.CalendarReminders
            .Include(x => x.Event).ThenInclude(e => e.Recurrence)
            .Include(x => x.Event).ThenInclude(e => e.Exceptions)
            .Include(x => x.Dispatches)
            .Where(x => !x.IsDeleted)
            .Where(x => !x.Event.IsDeleted)
            .Where(x => x.Event.Status == EventStatus.Confirmed)
            .ToListAsync(cancellationToken);

        var sentCount = 0;

        foreach (var reminder in reminders)
        {
            var evt = reminder.Event;
            var occurrences = RecurrenceExpander.Expand(evt, rangeFrom, rangeTo).ToList();

            foreach (var (startAt, _, _) in occurrences)
            {
                var triggerAt = startAt.AddMinutes(-reminder.OffsetMinutes);

                if (triggerAt > now)
                    continue;

                if (triggerAt < now.AddHours(-24))
                    continue;

                var alreadySent = reminder.Dispatches.Any(x =>
                    x.OccurrenceStartAt == startAt);

                if (alreadySent)
                    continue;

                var isRecurring = evt.Recurrence is not null
                    && evt.Recurrence.Type != RecurrenceType.None;

                if (!isRecurring && reminder.IsSent)
                    continue;

                await CalendarReminderNotificationHelper.SendToCreatorAsync(
                    context,
                    dateTime,
                    smsService,
                    evt,
                    reminder,
                    startAt,
                    cancellationToken);

                var dispatch = new CalendarReminderDispatch
                {
                    ReminderId = reminder.Id,
                    OccurrenceStartAt = startAt,
                    SentAt = now
                };

                context.CalendarReminderDispatches.Add(dispatch);
                reminder.Dispatches.Add(dispatch);

                if (!isRecurring)
                {
                    reminder.IsSent = true;
                    reminder.SentAt = now;
                }

                sentCount++;
            }
        }

        if (sentCount > 0)
            await context.SaveChangesAsync(cancellationToken);

        return sentCount;
    }
}

