namespace Application.Features.Command;

/// <summary>Handles adding a reminder to a calendar event (F1).</summary>
public class EventAddReminderCommandHandler(
    IApplicationDbContext context,
    ICurrentUserService currentUser)
    : IRequestHandler<EventAddReminderCommand, Result<int>>
{
    /// <inheritdoc />
    public async Task<Result<int>> Handle(
        EventAddReminderCommand request,
        CancellationToken cancellationToken)
    {
        try
        {
            var model = request.Model;
            var userId = currentUser.UserId();

            var validationError = CalendarAccessHelper.ValidateReminderInput(
                model.OffsetMinutes,
                model.Channel);

            if (validationError is not null)
                return validationError;

            var entity = await context.CalendarEvents
                .Include(x => x.Calendar)
                .Include(x => x.Reminders)
                .FirstOrDefaultAsync(x => x.Id == model.EventId, cancellationToken);

            if (entity is null)
                return EventErrors.NotFound;

            var positionIds = await CalendarAccessHelper.GetUserPositionIdsAsync(
                context, userId, cancellationToken);

            if (!await CalendarAccessHelper.CanEditEventAsync(
                    entity, userId, currentUser, positionIds, cancellationToken))
                return EventErrors.ReminderAddForbidden;

            var phoneError = await CalendarAccessHelper.ValidateCreatorPhoneForSmsAsync(
                context,
                entity.CreatedByUserId,
                model.Channel,
                cancellationToken);

            if (phoneError is not null)
                return phoneError;

            var softDeleted = await context.CalendarReminders
                .IgnoreQueryFilters()
                .FirstOrDefaultAsync(x =>
                    x.EventId == entity.Id
                    && x.IsDeleted
                    && x.OffsetMinutes == model.OffsetMinutes
                    && x.Channel == model.Channel,
                    cancellationToken);

            if (softDeleted is not null)
            {
                softDeleted.IsDeleted = false;
                softDeleted.DeleteBy = null;
                softDeleted.DeleteDate = null;
                softDeleted.IsSent = false;
                softDeleted.SentAt = null;

                await context.SaveChangesAsync(cancellationToken);
                return Result<int>.Success(softDeleted.Id);
            }

            var duplicate = entity.Reminders.Any(x =>
                x.OffsetMinutes == model.OffsetMinutes
                && x.Channel == model.Channel);

            if (duplicate)
                return EventErrors.ReminderAlreadyExists;

            var reminder = new CalendarReminder
            {
                EventId = entity.Id,
                OffsetMinutes = model.OffsetMinutes,
                Channel = model.Channel
            };

            entity.Reminders.Add(reminder);
            await context.SaveChangesAsync(cancellationToken);

            return Result<int>.Success(reminder.Id);
        }
        catch (Exception ex)
        {
            Log.Error($"EventAddReminder: {ex.Message}", ex);
            return Error.ServerError;
        }
    }
}

