    public static async Task SendToCreatorAsync(
        IApplicationDbContext context,
        IDateTimeService dateTime,
        ISmsService smsService,
        CalendarEvent calendarEvent,
        CalendarReminder reminder,
        DateTime occurrenceStartAt,
        CancellationToken cancellationToken)
    {
        var creatorId = calendarEvent.CreatedByUserId;
        var subject = "یادآوری رویداد";
        var content = $"یادآوری: {calendarEvent.Title} — شروع در {occurrenceStartAt:yyyy/MM/dd HH:mm}";
        var smsBody = $"یادآوری رویداد: {calendarEvent.Title} — {occurrenceStartAt:yyyy/MM/dd HH:mm}";

        if (reminder.Channel == ReminderChannel.Sms)
        {
            var phone = await context.AppUsers
                .AsNoTracking()
                .Where(x => x.Id == creatorId)
                .Select(x => x.PhoneNumber)
                .FirstOrDefaultAsync(cancellationToken);

            if (!string.IsNullOrWhiteSpace(phone))
                await smsService.SendAsync(phone, smsBody, cancellationToken);

            return;
        }

        var notification = new NotificationCenter(
            calendarEvent.Id,
            subject,
            content,
