/// <summary>
/// Configuration for the calendar reminder background processor.
/// </summary>
public sealed class ReminderOption
{
    /// <summary>Gets or sets seconds to wait before the first reminder scan after startup.</summary>
    public int InitialDelaySeconds { get; set; } = 30;

    /// <summary>Gets or sets minutes between reminder scans.</summary>
    public int IntervalMinutes { get; set; } = 1;
}

using Microsoft.Extensions.Configuration;
using Microsoft.Extensions.Options;

namespace Application.Option;

/// <summary>
/// Binds <see cref="ReminderOption"/> from application configuration.
/// </summary>
public class ReminderOptionsSetup : IConfigureOptions<ReminderOption>
{
    private const string SectionName = "Reminder";
    private readonly IConfiguration _configuration;

    /// <summary>
    /// Initializes a new instance of the <see cref="ReminderOptionsSetup"/> class.
    /// </summary>
    /// <param name="configuration">Application configuration.</param>
    public ReminderOptionsSetup(IConfiguration configuration)
    {
        _configuration = configuration;
    }

    /// <inheritdoc />
    public void Configure(ReminderOption options)
    {
        _configuration.GetSection(SectionName).Bind(options);

        if (options.InitialDelaySeconds < 0)
            options.InitialDelaySeconds = 0;

        if (options.IntervalMinutes < 1)
            options.IntervalMinutes = 1;
    }
}

using Application.Features.CalendarSupport;
using Application.Option;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Hosting;
using Microsoft.Extensions.Logging;
using Microsoft.Extensions.Options;

namespace Infrastructure.Services;

/// <summary>
/// Periodically scans for due calendar reminders and dispatches them to event creators.
/// </summary>
public class ReminderBackgroundService : BackgroundService
{
    private readonly IServiceScopeFactory _scopeFactory;
    private readonly ILogger<ReminderBackgroundService> _logger;
    private readonly ReminderOption _options;

    /// <summary>
    /// Initializes a new instance of the <see cref="ReminderBackgroundService"/> class.
    /// </summary>
    public ReminderBackgroundService(
        IServiceScopeFactory scopeFactory,
        ILogger<ReminderBackgroundService> logger,
        IOptions<ReminderOption> options)
    {
        _scopeFactory = scopeFactory;
        _logger = logger;
        _options = options.Value;
    }

    /// <inheritdoc />
    protected override async Task ExecuteAsync(CancellationToken stoppingToken)
    {
        _logger.LogInformation(
            "Reminder Background Service started. Initial delay: {InitialDelay}s, interval: {Interval} min.",
            _options.InitialDelaySeconds,
            _options.IntervalMinutes);

        if (_options.InitialDelaySeconds > 0)
        {
            try
            {
                await Task.Delay(TimeSpan.FromSeconds(_options.InitialDelaySeconds), stoppingToken);
            }
            catch (OperationCanceledException)
            {
                return;
            }
        }

        while (!stoppingToken.IsCancellationRequested)
        {
            await RunOnceAsync(stoppingToken);

            try
            {
                await Task.Delay(TimeSpan.FromMinutes(_options.IntervalMinutes), stoppingToken);
            }
            catch (OperationCanceledException)
            {
                break;
            }
        }

        _logger.LogInformation("Reminder Background Service stopped.");
    }

    private async Task RunOnceAsync(CancellationToken stoppingToken)
    {
        try
        {
            using var scope = _scopeFactory.CreateScope();
            var processor = scope.ServiceProvider.GetRequiredService<CalendarReminderDueProcessor>();
            var sent = await processor.ProcessDueAsync(stoppingToken);

            if (sent > 0)
                _logger.LogInformation("Reminder scan dispatched {Count} reminder(s).", sent);
        }
        catch (Exception ex)
        {
            _logger.LogError(ex, "Reminder scan failed; will retry after interval.");
        }
    }
}

