namespace Domain.Models;

/// <summary>
/// Represents a file attached to a calendar event.
/// </summary>
public class CalendarAttachment : Entity<int>
{
    /// <summary>Gets or sets the parent event id.</summary>
    public int EventId { get; set; }

    /// <summary>Gets or sets the parent event.</summary>
    public CalendarEvent Event { get; set; } = null!;

    /// <summary>Gets or sets the user who uploaded the file.</summary>
    public int UploadedByUserId { get; set; }

    /// <summary>Gets or sets the uploader user.</summary>
    public AppUser UploadedByUser { get; set; } = null!;

    /// <summary>Gets or sets the original file name.</summary>
    public string FileName { get; set; } = string.Empty;

    /// <summary>Gets or sets the relative storage path under CalendarFiles.</summary>
    public string FileUrl { get; set; } = string.Empty;

    /// <summary>Gets or sets the file size in bytes.</summary>
    public long SizeBytes { get; set; }

    /// <summary>Gets or sets the MIME content type.</summary>
    public string ContentType { get; set; } = string.Empty;
}

namespace Domain.Models;

/// <summary>
/// Represents a note attached to a calendar event.
/// </summary>
public class CalendarEventNote : Entity<int>
{
    /// <summary>Gets or sets the parent event id.</summary>
    public int EventId { get; set; }

    /// <summary>Gets or sets the parent event.</summary>
    public CalendarEvent Event { get; set; } = null!;

    /// <summary>Gets or sets the author user id.</summary>
    public int AuthorUserId { get; set; }

    /// <summary>Gets or sets the author user.</summary>
    public AppUser AuthorUser { get; set; } = null!;

    /// <summary>Gets or sets the note text.</summary>
    public string Text { get; set; } = string.Empty;
}

namespace Infrastructure.Data.Configuration.CalendarEntities;

public class CalendarAttachmentConfiguration : IEntityTypeConfiguration<CalendarAttachment>
{
    public void Configure(EntityTypeBuilder<CalendarAttachment> builder)
    {
        builder.Property(x => x.FileName)
            .IsRequired()
            .HasMaxLength(260);

        builder.Property(x => x.FileUrl)
            .IsRequired()
            .HasMaxLength(500);

        builder.Property(x => x.ContentType)
            .IsRequired()
            .HasMaxLength(100);

        builder.HasOne(x => x.Event)
            .WithMany(x => x.Attachments)
            .HasForeignKey(x => x.EventId)
            .OnDelete(DeleteBehavior.Cascade);

        builder.HasOne(x => x.UploadedByUser)
            .WithMany()
            .HasForeignKey(x => x.UploadedByUserId)
            .OnDelete(DeleteBehavior.Restrict);

        builder.HasIndex(x => x.EventId);
    }
}

namespace Infrastructure.Data.Configuration.CalendarEntities;

public class CalendarEventNoteConfiguration : IEntityTypeConfiguration<CalendarEventNote>
{
    public void Configure(EntityTypeBuilder<CalendarEventNote> builder)
    {
        builder.Property(x => x.Text)
            .IsRequired()
            .HasMaxLength(2000);

        builder.HasOne(x => x.Event)
            .WithMany(x => x.Notes)
            .HasForeignKey(x => x.EventId)
            .OnDelete(DeleteBehavior.Cascade);

        builder.HasOne(x => x.AuthorUser)
            .WithMany()
            .HasForeignKey(x => x.AuthorUserId)
            .OnDelete(DeleteBehavior.Restrict);

        builder.HasIndex(x => x.EventId);
    }
}

