using Application.DTOs.Calendar;
using Application.Errors;
using Application.Option;
using Domain.Models;
using Microsoft.AspNetCore.Http;

namespace Application.Features.CalendarSupport;

/// <summary>
/// Helpers for calendar attachment and note validation and mapping.
/// </summary>
public static class CalendarAttachmentHelper
{
    public const long MaxAttachmentBytes = 10 * 1024 * 1024;
    public const int MaxNoteLength = 2000;

    private static readonly HashSet<string> AllowedExtensions = new(StringComparer.OrdinalIgnoreCase)
    {
        ".jpg", ".jpeg", ".png", ".pdf", ".doc", ".docx"
    };

    /// <summary>
    /// Validates an uploaded attachment file against size and extension rules.
    /// </summary>
    public static Error? ValidateFile(IFormFile? file)
    {
        if (file is null || file.Length <= 0)
            return EventErrors.AttachmentFileRequired;

        if (file.Length > MaxAttachmentBytes)
            return EventErrors.AttachmentTooLarge;

        var extension = Path.GetExtension(file.FileName);
        if (string.IsNullOrWhiteSpace(extension) || !AllowedExtensions.Contains(extension))
            return EventErrors.AttachmentTypeNotAllowed;

        return null;
    }

    /// <summary>
    /// Validates note text for create/update.
    /// </summary>
    public static Error? ValidateNoteText(string? text)
    {
        if (string.IsNullOrWhiteSpace(text))
            return EventErrors.NoteTextRequired;

        if (text.Trim().Length > MaxNoteLength)
            return EventErrors.NoteTextTooLong;

        return null;
    }

    /// <summary>
    /// Maps an attachment entity to a DTO with a public URL.
    /// </summary>
    public static AttachmentDto ToDto(CalendarAttachment attachment, PathOption pathOption) =>
        new()
        {
            Id = attachment.Id,
            FileName = attachment.FileName,
            FileUrl = BuildPublicUrl(pathOption.CalendarFilesUrl, attachment.FileUrl),
            SizeBytes = attachment.SizeBytes,
            UploadedAt = attachment.CreateDate
        };

    /// <summary>
    /// Maps a note entity to a DTO.
    /// </summary>
    public static NoteDto ToDto(CalendarEventNote note) =>
        new()
        {
            Id = note.Id,
            Text = note.Text,
            AuthorUserId = note.AuthorUserId,
            CreatedAt = note.CreateDate
        };

    /// <summary>
    /// Builds a public URL from the configured virtual root and relative storage path.
    /// </summary>
    public static string BuildPublicUrl(string? filesUrl, string relativePath)
    {
        var root = string.IsNullOrWhiteSpace(filesUrl) ? "/calendar_files" : filesUrl.TrimEnd('/');
        var relative = relativePath.Replace('\\', '/').TrimStart('/');
        return $"{root}/{relative}";
    }

    /// <summary>
    /// Saves an uploaded file under CalendarFiles/{eventId}/ and returns the relative path.
    /// </summary>
    public static async Task<(string RelativePath, string StoredFileName)> SaveFileAsync(
        string calendarFilesRoot,
        int eventId,
        IFormFile file,
        CancellationToken cancellationToken)
    {
        var eventDir = Path.Combine(calendarFilesRoot, eventId.ToString());
        Directory.CreateDirectory(eventDir);

        var safeName = Path.GetFileName(file.FileName);
        var storedName = safeName;
        var fullPath = Path.Combine(eventDir, storedName);
        var counter = 0;

        while (File.Exists(fullPath))
        {
            storedName = $"{counter++}_{safeName}";
            fullPath = Path.Combine(eventDir, storedName);
        }

        await using (var stream = new FileStream(fullPath, FileMode.Create, FileAccess.Write, FileShare.None))
        {
            await file.CopyToAsync(stream, cancellationToken);
        }

        var relative = Path.Combine(eventId.ToString(), storedName).Replace('\\', '/');
        return (relative, storedName);
    }
}

