public record EventAddAttachmentCommand(int EventId, IFormFile File)
    : IRequest<Result<AttachmentDto>>;

using Application.DTOs.Calendar;
using Application.Errors;
using Application.Features.CalendarSupport;
using Application.Option;
using Application.Services;
using Domain.Models;
using Microsoft.Extensions.Options;

namespace Application.Features.Command;

/// <summary>Handles uploading a calendar event attachment (G1).</summary>
public class EventAddAttachmentCommandHandler(
    IApplicationDbContext context,
    ICurrentUserService currentUser,
    IOptions<PathOption> pathOption)
    : IRequestHandler<EventAddAttachmentCommand, Result<AttachmentDto>>
{
    /// <inheritdoc />
    public async Task<Result<AttachmentDto>> Handle(
        EventAddAttachmentCommand request,
        CancellationToken cancellationToken)
    {
        try
        {
            var userId = currentUser.UserId();
            var fileError = CalendarAttachmentHelper.ValidateFile(request.File);
            if (fileError is not null)
                return fileError;

            var entity = await context.CalendarEvents
                .Include(x => x.Calendar)
                .FirstOrDefaultAsync(x => x.Id == request.EventId, cancellationToken);

            if (entity is null)
                return EventErrors.NotFound;

            var positionIds = await CalendarAccessHelper.GetUserPositionIdsAsync(
                context, userId, cancellationToken);

            if (!await CalendarAccessHelper.CanEditEventAsync(
                    entity, userId, currentUser, positionIds, cancellationToken))
                return EventErrors.AttachmentAddForbidden;

            var root = pathOption.Value.CalendarFiles;
            if (string.IsNullOrWhiteSpace(root))
                return Error.ServerError;

            var (relativePath, _) = await CalendarAttachmentHelper.SaveFileAsync(
                root,
                entity.Id,
                request.File,
                cancellationToken);

            var attachment = new CalendarAttachment
            {
                EventId = entity.Id,
                UploadedByUserId = userId,
                FileName = Path.GetFileName(request.File.FileName),
                FileUrl = relativePath,
                SizeBytes = request.File.Length,
                ContentType = string.IsNullOrWhiteSpace(request.File.ContentType)
                    ? "application/octet-stream"
                    : request.File.ContentType
            };

            await context.CalendarAttachments.AddAsync(attachment, cancellationToken);
            await context.SaveChangesAsync(cancellationToken);

            return Result<AttachmentDto>.Success(
                CalendarAttachmentHelper.ToDto(attachment, pathOption.Value));
        }
        catch (Exception ex)
        {
            Log.Error($"EventAddAttachment: {ex.Message}", ex);
            return Error.ServerError;
        }
    }
}

