/// <summary>Handles creating or updating a calendar event note (G4).</summary>
public class EventUpsertNoteCommandHandler(
    IApplicationDbContext context,
    ICurrentUserService currentUser)
    : IRequestHandler<EventUpsertNoteCommand, Result<int>>
{
    /// <inheritdoc />
    public async Task<Result<int>> Handle(
        EventUpsertNoteCommand request,
        CancellationToken cancellationToken)
    {
        try
        {
            var model = request.Model;
            var userId = currentUser.UserId();

            var textError = CalendarAttachmentHelper.ValidateNoteText(model.Text);
            if (textError is not null)
                return textError;

            var entity = await context.CalendarEvents
                .Include(x => x.Participants)
                .FirstOrDefaultAsync(x => x.Id == model.EventId, cancellationToken);

            if (entity is null)
                return EventErrors.NotFound;

            if (!CalendarAccessHelper.CanViewEvent(entity, userId))
                return EventErrors.NoteAddForbidden;

            var text = model.Text.Trim();

            if (model.NoteId is null or 0)
            {
                var note = new CalendarEventNote
                {
                    EventId = entity.Id,
                    AuthorUserId = userId,
                    Text = text
                };

                await context.CalendarEventNotes.AddAsync(note, cancellationToken);
                await context.SaveChangesAsync(cancellationToken);
                return Result<int>.Success(note.Id);
            }

            var existing = await context.CalendarEventNotes
                .FirstOrDefaultAsync(x =>
                    x.Id == model.NoteId.Value
                    && x.EventId == entity.Id,
                    cancellationToken);

            if (existing is null)
                return EventErrors.NoteNotFound;

            if (existing.AuthorUserId != userId)
                return EventErrors.NoteEditForbidden;

            existing.Text = text;
            await context.SaveChangesAsync(cancellationToken);
            return Result<int>.Success(existing.Id);
        }
        catch (Exception ex)
        {
            Log.Error($"EventUpsertNote: {ex.Message}", ex);
            return Error.ServerError;
        }
    }
}

