/// <summary>Handles event detail query.</summary>
public class EventGetByIdQueryHandler(
    IApplicationDbContext context,
    ICurrentUserService currentUser,
    IOptions<PathOption> pathOption)
    : IRequestHandler<EventGetByIdQuery, Result<EventDetailDto>>
{
    /// <inheritdoc />
    public async Task<Result<EventDetailDto>> Handle(
        EventGetByIdQuery request,
        CancellationToken cancellationToken)
    {
        try
        {
            var userId = currentUser.UserId();

            var entity = await context.CalendarEvents
                .AsNoTracking()
                .Include(x => x.Calendar)
                .Include(x => x.Participants).ThenInclude(x => x.User)
                .Include(x => x.Reminders).ThenInclude(r => r.Dispatches)
                .Include(x => x.Recurrence)
                .Include(x => x.Attachments)
                .Include(x => x.Notes)
                .FirstOrDefaultAsync(x => x.Id == request.Id, cancellationToken);

            if (entity is null)
                return EventErrors.NotFound;

            if (!CalendarAccessHelper.CanViewEvent(entity, userId))
                return EventErrors.ViewForbidden;

            var dto = new EventDetailDto
            {
                Id = entity.Id,
                CalendarId = entity.CalendarId,
                Title = entity.Title,
                Description = entity.Description,
                Location = entity.Location,
                Type = entity.Type,
                StartAt = entity.StartAt,
                EndAt = entity.EndAt,
                IsAllDay = entity.IsAllDay,
                IsPersonal = entity.IsPersonal,
                VisibleOnlyToParticipants = entity.VisibleOnlyToParticipants,
                Status = entity.Status,
                CreatedByUserId = entity.CreatedByUserId,
                Participants = entity.Participants.Select(p => new ParticipantDto
                {
                    UserId = p.UserId,
                    FullName = p.User.Name,
                    Response = p.Response
                }).ToList(),
                Reminders = entity.Reminders.Select(CalendarAccessHelper.ToReminderDto).ToList(),
                Recurrence = entity.Recurrence is null
                    ? null
                    : new RecurrenceDto
                    {
                        Type = entity.Recurrence.Type,
                        Interval = entity.Recurrence.Interval,
                        WeekDays = ParseWeekDays(entity.Recurrence.WeekDays),
                        EndDate = entity.Recurrence.EndDate,
                        OccurrenceCount = entity.Recurrence.OccurrenceCount
                    },
                Attachments = entity.Attachments
                    .Select(x => CalendarAttachmentHelper.ToDto(x, pathOption.Value))
                    .ToList(),
                Notes = entity.Notes
                    .OrderBy(x => x.CreateDate)
                    .Select(CalendarAttachmentHelper.ToDto)
                    .ToList()
            };

            return Result<EventDetailDto>.Success(dto);
        }
        catch (Exception ex)
        {
            Log.Error($"EventGetById: {ex.Message}", ex);
            return Error.ServerError;
        }
    }

    private static List<int>? ParseWeekDays(string? weekDays)
    {
        if (string.IsNullOrWhiteSpace(weekDays))
            return null;

        return weekDays
            .Split(',', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries)
            .Select(x => int.TryParse(x, out var d) ? d : -1)
            .Where(x => x >= 0)
            .ToList();
    }
}

