using Application.Data;
using Domain.Models;

namespace Application.Features.CalendarSupport;

/// <summary>
/// Detects scheduling conflicts for calendar users (creators and non-declined participants).
/// </summary>
public static class EventConflictHelper
{
    /// <summary>
    /// Returns the display name of the first user among <paramref name="userIds"/>
    /// who already has a Confirmed overlapping commitment, or null if none.
    /// </summary>
    /// <remarks>
    /// A user is busy when they are the <see cref="CalendarEvent.CreatedByUserId"/> of a
    /// Confirmed event in the range, or a participant with <see cref="ParticipantResponse"/>
    /// other than <see cref="ParticipantResponse.Declined"/>. Soft-deleted rows are excluded
    /// by the global filter. Recurrence expansion is not applied (base StartAt/EndAt only).
    /// </remarks>
    /// <param name="context">Application database context.</param>
    /// <param name="userIds">User ids that would be committed to the new range.</param>
    /// <param name="startAt">Proposed range start (exclusive end overlap rule).</param>
    /// <param name="endAt">Proposed range end.</param>
    /// <param name="excludeEventId">Optional event id to ignore (e.g. the event being updated).</param>
    /// <param name="cancellationToken">Cancellation token.</param>
    /// <returns>Conflicting user display name, or null.</returns>
    public static async Task<string?> FindConflictUserNameAsync(
        IApplicationDbContext context,
        IEnumerable<int> userIds,
        DateTime startAt,
        DateTime endAt,
        int? excludeEventId,
        CancellationToken cancellationToken)
    {
        var ids = userIds.Distinct().ToList();
        if (ids.Count == 0)
            return null;

        var creatorQuery = context.CalendarEvents
            .AsNoTracking()
            .Where(e => ids.Contains(e.CreatedByUserId))
            .Where(e => e.Status == EventStatus.Confirmed)
            .Where(e => e.StartAt < endAt && e.EndAt > startAt);

        if (excludeEventId.HasValue)
            creatorQuery = creatorQuery.Where(e => e.Id != excludeEventId.Value);

        var creatorName = await creatorQuery
            .Select(e => e.CreatedByUser.Name)
            .FirstOrDefaultAsync(cancellationToken);

        if (!string.IsNullOrWhiteSpace(creatorName))
            return creatorName;

        var participantQuery = context.CalendarParticipants
            .AsNoTracking()
            .Where(p => ids.Contains(p.UserId))
            .Where(p => p.Response != ParticipantResponse.Declined)
            .Where(p => p.Event.Status == EventStatus.Confirmed)
