namespace Domain.Models;

/// <summary>
/// Represents a starred contact for quick calendar invites.
/// </summary>
public class FavoriteContact : Entity<int>
{
    /// <summary>Gets or sets the user who starred the contact.</summary>
    public int OwnerUserId { get; set; }

    /// <summary>Gets or sets the owner user.</summary>
    public AppUser OwnerUser { get; set; } = null!;

    /// <summary>Gets or sets the starred target user id.</summary>
    public int TargetUserId { get; set; }

    /// <summary>Gets or sets the target user.</summary>
    public AppUser TargetUser { get; set; } = null!;
}

namespace Domain.Models;

/// <summary>
/// Represents a company holiday or leave entry for a given scope.
/// </summary>
public class CalendarHoliday : Entity<int>
{
    /// <summary>Gets or sets the holiday title.</summary>
    public string Title { get; set; } = string.Empty;

    /// <summary>Gets or sets the start time (UTC).</summary>
    public DateTime StartAt { get; set; }

    /// <summary>Gets or sets the end time (UTC).</summary>
    public DateTime EndAt { get; set; }

    /// <summary>Gets or sets whether the holiday is all-day.</summary>
    public bool IsAllDay { get; set; } = true;

    /// <summary>Gets or sets the holiday scope.</summary>
    public CalendarHolidayScope Scope { get; set; } = CalendarHolidayScope.Organization;

    /// <summary>
    /// Gets or sets the scope entity id (required for Unit/Project; null for Organization).
    /// </summary>
    public int? ScopeId { get; set; }
}

namespace Infrastructure.Data.Configuration.CalendarEntities;

/// <summary>EF configuration for <see cref="FavoriteContact"/>.</summary>
public class FavoriteContactConfiguration : IEntityTypeConfiguration<FavoriteContact>
{
    /// <inheritdoc />
    public void Configure(EntityTypeBuilder<FavoriteContact> builder)
    {
        builder.HasOne(x => x.OwnerUser)
            .WithMany()
            .HasForeignKey(x => x.OwnerUserId)
            .OnDelete(DeleteBehavior.Restrict);

        builder.HasOne(x => x.TargetUser)
            .WithMany()
            .HasForeignKey(x => x.TargetUserId)
            .OnDelete(DeleteBehavior.Restrict);

        builder.HasIndex(x => new { x.OwnerUserId, x.TargetUserId })
            .IsUnique()
            .HasFilter("[IsDeleted] = 0");
    }
}

namespace Infrastructure.Data.Configuration.CalendarEntities;

/// <summary>EF configuration for <see cref="CalendarHoliday"/>.</summary>
public class CalendarHolidayConfiguration : IEntityTypeConfiguration<CalendarHoliday>
{
    /// <inheritdoc />
    public void Configure(EntityTypeBuilder<CalendarHoliday> builder)
    {
        builder.Property(x => x.Title)
            .IsRequired()
            .IsUnicode()
            .HasMaxLength(200);

        builder.Property(x => x.Scope)
            .IsRequired();

        builder.HasIndex(x => new { x.Scope, x.ScopeId, x.StartAt });
    }
}

