using Application.DTOs.Calendar;

namespace Application.Features.Command;

/// <summary>Command to add a favorite contact (H2). Idempotent on duplicate.</summary>
/// <param name="Model">Favorite add input.</param>
public record FavoriteAddCommand(FavoriteAddDto Model) : IRequest<Result<int>>;

/// <summary>Validates <see cref="FavoriteAddCommand"/>.</summary>
public class FavoriteAddCommandValidator : AbstractValidator<FavoriteAddCommand>
{
    /// <summary>Initializes validator rules.</summary>
    public FavoriteAddCommandValidator()
    {
        RuleFor(x => x.Model.TargetUserId)
            .GreaterThan(0).WithMessage("شناسه کاربر الزامی است");
    }
}

using Application.Errors;
using Application.Services;
using Domain.Models;

namespace Application.Features.Command;

/// <summary>Handles adding a favorite contact (H2).</summary>
public class FavoriteAddCommandHandler(
    IApplicationDbContext context,
    ICurrentUserService currentUser)
    : IRequestHandler<FavoriteAddCommand, Result<int>>
{
    /// <inheritdoc />
    public async Task<Result<int>> Handle(
        FavoriteAddCommand request,
        CancellationToken cancellationToken)
    {
        try
        {
            var ownerId = currentUser.UserId();
            var targetId = request.Model.TargetUserId;

            if (targetId == ownerId)
                return FavoriteErrors.CannotFavoriteSelf;

            var targetExists = await context.AppUsers
                .AsNoTracking()
                .AnyAsync(x => x.Id == targetId, cancellationToken);

            if (!targetExists)
                return FavoriteErrors.TargetUserNotFound;

            var active = await context.FavoriteContacts
                .FirstOrDefaultAsync(
                    x => x.OwnerUserId == ownerId && x.TargetUserId == targetId,
                    cancellationToken);

            if (active is not null)
                return Result<int>.Success(active.Id);

            var softDeleted = await context.FavoriteContacts
                .IgnoreQueryFilters()
                .FirstOrDefaultAsync(
                    x => x.OwnerUserId == ownerId
                         && x.TargetUserId == targetId
                         && x.IsDeleted,
                    cancellationToken);

            if (softDeleted is not null)
            {
                softDeleted.IsDeleted = false;
                softDeleted.DeleteBy = null;
                softDeleted.DeleteDate = null;
                await context.SaveChangesAsync(cancellationToken);
                return Result<int>.Success(softDeleted.Id);
            }

            var entity = new FavoriteContact
            {
                OwnerUserId = ownerId,
                TargetUserId = targetId
            };

            await context.FavoriteContacts.AddAsync(entity, cancellationToken);
            await context.SaveChangesAsync(cancellationToken);

            return Result<int>.Success(entity.Id);
        }
        catch (Exception ex)
        {
            Log.Error($"FavoriteAdd: {ex.Message}", ex);
            return Error.ServerError;
        }
    }
}

namespace Application.Features.Command;

/// <summary>Command to soft-delete a favorite contact (H3).</summary>
/// <param name="Id">Favorite row id.</param>
public record FavoriteDeleteCommand(int Id) : IRequest<Result<bool>>;

using Application.Errors;
using Application.Services;

namespace Application.Features.Command;

/// <summary>Handles soft-deleting a favorite contact (H3).</summary>
public class FavoriteDeleteCommandHandler(
    IApplicationDbContext context,
    ICurrentUserService currentUser)
    : IRequestHandler<FavoriteDeleteCommand, Result<bool>>
{
    /// <inheritdoc />
    public async Task<Result<bool>> Handle(
        FavoriteDeleteCommand request,
        CancellationToken cancellationToken)
    {
        try
        {
            var entity = await context.FavoriteContacts
                .FirstOrDefaultAsync(x => x.Id == request.Id, cancellationToken);

            if (entity is null)
                return FavoriteErrors.NotFound;

            if (entity.OwnerUserId != currentUser.UserId())
                return FavoriteErrors.DeleteForbidden;

            entity.IsDeleted = true;
            entity.DeleteDate = DateTime.Now;

            await context.SaveChangesAsync(cancellationToken);
            return Result<bool>.Success(true);
        }
        catch (Exception ex)
        {
            Log.Error($"FavoriteDelete: {ex.Message}", ex);
            return Error.ServerError;
        }
    }
}

using Application.DTOs.Calendar;

namespace Application.Features.Query;

/// <summary>Query to list current user's favorite contacts (H1).</summary>
public record FavoritesListQuery() : IRequest<Result<List<FavoriteContactDto>>>;

using Application.DTOs.Calendar;
using Application.Services;

namespace Application.Features.Query;

/// <summary>Handles listing favorite contacts (H1).</summary>
public class FavoritesListQueryHandler(
    IApplicationDbContext context,
    ICurrentUserService currentUser)
    : IRequestHandler<FavoritesListQuery, Result<List<FavoriteContactDto>>>
{
    /// <inheritdoc />
    public async Task<Result<List<FavoriteContactDto>>> Handle(
        FavoritesListQuery request,
        CancellationToken cancellationToken)
    {
        try
        {
            var ownerId = currentUser.UserId();

            var items = await context.FavoriteContacts
                .AsNoTracking()
                .Where(x => x.OwnerUserId == ownerId)
                .OrderBy(x => x.TargetUser.Name)
                .Select(x => new FavoriteContactDto
                {
                    Id = x.Id,
                    TargetUserId = x.TargetUserId,
                    TargetFullName = x.TargetUser.Name
                })
                .ToListAsync(cancellationToken);

            return Result<List<FavoriteContactDto>>.Success(items);
        }
        catch (Exception ex)
        {
            Log.Error($"FavoritesList: {ex.Message}", ex);
            return Error.ServerError;
        }
    }
}

