using Application.Errors;
using Domain.Models;

namespace Application.Features.Command;

/// <summary>Handles creating a calendar holiday.</summary>
public class HolidayCreateCommandHandler(IApplicationDbContext context)
    : IRequestHandler<HolidayCreateCommand, Result<int>>
{
    /// <inheritdoc />
    public async Task<Result<int>> Handle(
        HolidayCreateCommand request,
        CancellationToken cancellationToken)
    {
        try
        {
            var model = request.Model;

            if (string.IsNullOrWhiteSpace(model.Title))
                return HolidayErrors.TitleRequired;

            if (model.Title.Trim().Length < 2)
                return HolidayErrors.TitleTooShort;

            if (model.EndAt <= model.StartAt)
                return HolidayErrors.InvalidTimeRange;

            if (!Enum.IsDefined(model.Scope))
                return HolidayErrors.InvalidScope;

            if (model.Scope is CalendarHolidayScope.Unit or CalendarHolidayScope.Project
                && (!model.ScopeId.HasValue || model.ScopeId.Value <= 0))
                return HolidayErrors.ScopeIdRequired;

            var entity = new CalendarHoliday
            {
                Title = model.Title.Trim(),
                StartAt = model.StartAt,
                EndAt = model.EndAt,
                IsAllDay = model.IsAllDay,
                Scope = model.Scope,
                ScopeId = model.Scope == CalendarHolidayScope.Organization
                    ? null
                    : model.ScopeId
            };

            await context.CalendarHolidays.AddAsync(entity, cancellationToken);
            await context.SaveChangesAsync(cancellationToken);

            return Result<int>.Success(entity.Id);
        }
        catch (Exception ex)
        {
            Log.Error($"HolidayCreate: {ex.Message}", ex);
            return Error.ServerError;
        }
    }
}

