namespace Application.Features.Query;

/// <summary>Query holidays overlapping a date range for a scope (H4).</summary>
/// <param name="From">Range start.</param>
/// <param name="To">Range end.</param>
/// <param name="Scope">Holiday scope.</param>
/// <param name="ScopeId">Required for Unit/Project.</param>
public record HolidaysRangeQuery(
    DateTime From,
    DateTime To,
    CalendarHolidayScope Scope,
    int? ScopeId) : IRequest<Result<List<CalendarHolidayDto>>>;

using Application.DTOs.Calendar;
using Application.Errors;

namespace Application.Features.Query;

/// <summary>Handles holiday range queries (H4).</summary>
public class HolidaysRangeQueryHandler(IApplicationDbContext context)
    : IRequestHandler<HolidaysRangeQuery, Result<List<CalendarHolidayDto>>>
{
    private static readonly TimeSpan MaxRange = TimeSpan.FromDays(92);

    /// <inheritdoc />
    public async Task<Result<List<CalendarHolidayDto>>> Handle(
        HolidaysRangeQuery request,
        CancellationToken cancellationToken)
    {
        try
        {
            if (request.To <= request.From)
                return HolidayErrors.InvalidRange;

            if (request.To - request.From > MaxRange)
                return HolidayErrors.RangeTooLarge;

            if (!Enum.IsDefined(request.Scope))
                return HolidayErrors.InvalidScope;

            if (request.Scope is CalendarHolidayScope.Unit or CalendarHolidayScope.Project
                && (!request.ScopeId.HasValue || request.ScopeId.Value <= 0))
                return HolidayErrors.ScopeIdRequired;

            var q = context.CalendarHolidays
                .AsNoTracking()
                .Where(x => x.Scope == request.Scope)
                .Where(x => x.StartAt < request.To && x.EndAt > request.From);

            if (request.Scope == CalendarHolidayScope.Organization)
                q = q.Where(x => x.ScopeId == null);
            else
                q = q.Where(x => x.ScopeId == request.ScopeId);

            var items = await q
                .OrderBy(x => x.StartAt)
                .Select(x => new CalendarHolidayDto
                {
                    Id = x.Id,
                    Title = x.Title,
                    StartAt = x.StartAt,
                    EndAt = x.EndAt,
                    IsAllDay = x.IsAllDay
                })
                .ToListAsync(cancellationToken);

            return Result<List<CalendarHolidayDto>>.Success(items);
        }
        catch (Exception ex)
        {
            Log.Error($"HolidaysRange: {ex.Message}", ex);
            return Error.ServerError;
        }
    }
}

