using Application.DTOs.Calendar;

namespace Application.Features.Query;

/// <summary>Query suggested free meeting slots for a set of users (I1).</summary>
/// <param name="UserIds">Participant user ids.</param>
/// <param name="From">Search range start.</param>
/// <param name="To">Search range end.</param>
/// <param name="DurationMinutes">Meeting length in minutes.</param>
public record SmartSlotsQuery(
    List<int> UserIds,
    DateTime From,
    DateTime To,
    int DurationMinutes) : IRequest<Result<List<SmartSlotDto>>>;

using Application.DTOs.Calendar;
using Application.Errors;
using Application.Features.CalendarSupport;
using Application.Services;

namespace Application.Features.Query;

/// <summary>Handles Smart Slot Finder (I1).</summary>
public class SmartSlotsQueryHandler(
    IApplicationDbContext context,
    ICurrentUserService currentUser)
    : IRequestHandler<SmartSlotsQuery, Result<List<SmartSlotDto>>>
{
    private const int StepMinutes = 15;
    private const int MaxSuggestions = 20;
    private const int MinDuration = 5;
    private const int MaxDuration = 480;

    /// <inheritdoc />
    public async Task<Result<List<SmartSlotDto>>> Handle(
        SmartSlotsQuery request,
        CancellationToken cancellationToken)
    {
        try
        {
            if (request.UserIds is null || request.UserIds.Count == 0)
                return EventErrors.AtLeastOneUserRequired;

            if (request.DurationMinutes < MinDuration || request.DurationMinutes > MaxDuration)
                return SmartSlotErrors.InvalidDuration;

            var rangeError = CalendarAccessHelper.ValidateTimeRange(request.From, request.To);
            if (rangeError is not null)
                return rangeError;

            var distinctIds = request.UserIds.Distinct().ToList();
            var existingCount = await context.AppUsers
                .AsNoTracking()
                .CountAsync(x => distinctIds.Contains(x.Id), cancellationToken);

            if (existingCount != distinctIds.Count)
                return EventErrors.InvalidUserInList;

            var bufferMinutes = await context.CalendarUserPreferences
                .AsNoTracking()
                .Where(x => x.UserId == currentUser.UserId())
                .Select(x => (int?)x.DefaultBufferMinutes)
                .FirstOrDefaultAsync(cancellationToken) ?? 0;

            var events = await context.CalendarEvents
                .AsNoTracking()
                .Include(x => x.Recurrence)
                .Include(x => x.Exceptions)
                .Include(x => x.Participants)
                .Where(x => x.Status == EventStatus.Confirmed)
                .Where(x =>
                    distinctIds.Contains(x.CreatedByUserId)
                    || x.Participants.Any(p =>
                        distinctIds.Contains(p.UserId)
                        && p.Response != ParticipantResponse.Declined))
                .ToListAsync(cancellationToken);

            var busyByUser = new Dictionary<int, List<(DateTime Start, DateTime End)>>();
            foreach (var userId in distinctIds)
            {
                var padded = events
                    .SelectMany(evt => CalendarBusyHelper.GetBusySlots(
                        evt, userId, request.From, request.To))
                    .Select(s => (
                        Start: s.StartAt.AddMinutes(-bufferMinutes),
                        End: s.EndAt.AddMinutes(bufferMinutes)))
                    .OrderBy(x => x.Start)
                    .ToList();

                busyByUser[userId] = MergeIntervals(padded);
            }

            var duration = TimeSpan.FromMinutes(request.DurationMinutes);
            var step = TimeSpan.FromMinutes(StepMinutes);
            var totalRangeTicks = Math.Max(1.0, (request.To - request.From).TotalMinutes);
            var suggestions = new List<SmartSlotDto>();

            for (var cursor = request.From;
                 cursor + duration <= request.To;
                 cursor += step)
            {
                cancellationToken.ThrowIfCancellationRequested();

                var end = cursor + duration;
                var freeCount = 0;

                foreach (var userId in distinctIds)
                {
                    if (!OverlapsAny(busyByUser[userId], cursor, end))
                        freeCount++;
                }

                if (freeCount == 0)
                    continue;

                var freeRatio = (double)freeCount / distinctIds.Count;
                var earliness = 1.0 - ((cursor - request.From).TotalMinutes / totalRangeTicks);
                var score = Math.Round((freeRatio * 0.85) + (earliness * 0.15), 2);

                // Prefer slots where everyone is free
                if (freeCount < distinctIds.Count && freeRatio < 1.0)
                {
                    // Still include partial fits only if majority free
                    if (freeRatio < 0.5)
                        continue;
                }

                suggestions.Add(new SmartSlotDto
                {
                    StartAt = cursor,
                    EndAt = end,
                    Score = score
                });
            }

            var top = suggestions
                .OrderByDescending(x => x.Score)
                .ThenBy(x => x.StartAt)
                .Take(MaxSuggestions)
                .ToList();

            return Result<List<SmartSlotDto>>.Success(top);
        }
        catch (Exception ex)
        {
            Log.Error($"SmartSlots: {ex.Message}", ex);
            return Error.ServerError;
        }
    }

    private static List<(DateTime Start, DateTime End)> MergeIntervals(
        List<(DateTime Start, DateTime End)> intervals)
    {
        if (intervals.Count == 0)
            return intervals;

        var merged = new List<(DateTime Start, DateTime End)>();
        var current = intervals[0];

        for (var i = 1; i < intervals.Count; i++)
        {
            var next = intervals[i];
            if (next.Start <= current.End)
            {
                if (next.End > current.End)
                    current = (current.Start, next.End);
            }
            else
            {
                merged.Add(current);
                current = next;
            }
        }

        merged.Add(current);
        return merged;
    }

    private static bool OverlapsAny(
        List<(DateTime Start, DateTime End)> intervals,
        DateTime start,
        DateTime end)
    {
        foreach (var slot in intervals)
        {
            if (slot.Start < end && slot.End > start)
                return true;
        }

        return false;
    }
}

