/// <summary>Handles upserting the current user's default buffer preference (I2).</summary>
public class BufferPreferenceUpsertCommandHandler(
    IApplicationDbContext context,
    ICurrentUserService currentUser)
    : IRequestHandler<BufferPreferenceUpsertCommand, Result<bool>>
{
    /// <inheritdoc />
    public async Task<Result<bool>> Handle(
        BufferPreferenceUpsertCommand request,
        CancellationToken cancellationToken)
    {
        try
        {
            var minutes = request.Model.DefaultBufferMinutes;
            if (minutes < 0 || minutes > 30)
                return SmartSlotErrors.InvalidBuffer;

            var userId = currentUser.UserId();
            var entity = await context.CalendarUserPreferences
                .FirstOrDefaultAsync(x => x.UserId == userId, cancellationToken);

            if (entity is null)
            {
                entity = new CalendarUserPreference
                {
                    UserId = userId,
                    DefaultBufferMinutes = minutes
                };
                await context.CalendarUserPreferences.AddAsync(entity, cancellationToken);
            }
            else
            {
                entity.DefaultBufferMinutes = minutes;
            }

            await context.SaveChangesAsync(cancellationToken);
            return Result<bool>.Success(true);
        }
        catch (Exception ex)
        {
            Log.Error($"BufferPreferenceUpsert: {ex.Message}", ex);
            return Error.ServerError;
        }
    }
}

