/// <summary>Endpoints for Smart Slot Finder and buffer preferences (Group I).</summary>
public class CalendarSmartSlotsEndPoint : ICarterModule
{
    /// <inheritdoc />
    public void AddRoutes(IEndpointRouteBuilder app)
    {
        app.MapGet("/Calendar/SmartSlots", async (
            string userIds,
            DateTime from,
            DateTime to,
            int durationMinutes,
            ISender sender,
            CancellationToken cancellationToken) =>
        {
            var ids = string.IsNullOrWhiteSpace(userIds)
                ? new List<int>()
                : userIds
                    .Split(',', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries)
                    .Select(x => int.TryParse(x, out var id) ? id : 0)
                    .Where(x => x > 0)
                    .ToList();

            var res = await sender.Send(
                new SmartSlotsQuery(ids, from, to, durationMinutes),
                cancellationToken);
            return CalendarProblemResults.FromResult(res);
        })
        .WithName("SmartSlots")
        .Produces<List<SmartSlotDto>>(StatusCodes.Status200OK)
        .ProducesProblem(StatusCodes.Status400BadRequest)
        .WithSummary("I1 — Find smart meeting slots")
        .RequireRateLimiting(RateLimitConst.RateFix)
        .RequireAuthorization();

        app.MapPut("/Calendar/Preferences/Buffer", async (
            [FromBody] BufferPreferenceDto request,
            ISender sender,
            CancellationToken cancellationToken) =>
        {
            var res = await sender.Send(
                new BufferPreferenceUpsertCommand(request),
                cancellationToken);
            return CalendarProblemResults.FromResult(res);
        })
        .WithName("BufferPreferenceUpsert")
        .Produces<bool>(StatusCodes.Status200OK)
        .ProducesProblem(StatusCodes.Status400BadRequest)
        .WithSummary("I2 — Save default meeting buffer preference")
        .RequireRateLimiting(RateLimitConst.RateFix)
        .RequireAuthorization();
    }
}

