using Application.Errors;
using Application.Features.CalendarSupport;
using Application.Services;
using Domain.Models;

namespace Application.Features.Command;

/// <summary>Handles replacing resource bookings on an event (J5).</summary>
public class EventBookResourcesCommandHandler(
    IApplicationDbContext context,
    ICurrentUserService currentUser)
    : IRequestHandler<EventBookResourcesCommand, Result<bool>>
{
    /// <inheritdoc />
    public async Task<Result<bool>> Handle(
        EventBookResourcesCommand request,
        CancellationToken cancellationToken)
    {
        try
        {
            var model = request.Model;
            var resourceIds = model.ResourceIds?
                .Where(id => id > 0)
                .Distinct()
                .ToList() ?? [];

            if (resourceIds.Count == 0)
                return ResourceErrors.AtLeastOneResourceRequired;

            if (model.ResourceIds!.Any(id => id <= 0))
                return ResourceErrors.InvalidResourceId;

            var userId = currentUser.UserId();

            var calendarEvent = await context.CalendarEvents
                .Include(x => x.Calendar)
                .FirstOrDefaultAsync(x => x.Id == model.EventId, cancellationToken);

            if (calendarEvent is null)
                return EventErrors.NotFound;

            var positionIds = await CalendarAccessHelper.GetUserPositionIdsAsync(
                context, userId, cancellationToken);

            if (!await CalendarAccessHelper.CanEditEventAsync(
                    calendarEvent, userId, currentUser, positionIds, cancellationToken))
                return ResourceErrors.BookForbidden;

            var resources = await context.CalendarResources
                .Where(x => resourceIds.Contains(x.Id))
                .ToListAsync(cancellationToken);

            if (resources.Count != resourceIds.Count)
                return ResourceErrors.NotFound;

            if (resources.Any(x => !x.IsActive))
                return ResourceErrors.Inactive;

            var hasConflict = await context.CalendarResourceBookings
                .AsNoTracking()
                .Where(b => resourceIds.Contains(b.ResourceId))
                .Where(b => b.EventId != calendarEvent.Id)
                .Where(b => b.Event.Status == EventStatus.Confirmed)
                .Where(b => b.Event.StartAt < calendarEvent.EndAt
                            && b.Event.EndAt > calendarEvent.StartAt)
                .AnyAsync(cancellationToken);

            if (hasConflict)
                return ResourceErrors.Conflict;

            var existing = await context.CalendarResourceBookings
                .Where(b => b.EventId == calendarEvent.Id)
                .ToListAsync(cancellationToken);

            foreach (var booking in existing)
            {
                booking.IsDeleted = true;
                booking.DeleteDate = DateTime.Now;
            }

            foreach (var resourceId in resourceIds)
            {
                await context.CalendarResourceBookings.AddAsync(
                    new CalendarResourceBooking
                    {
                        EventId = calendarEvent.Id,
                        ResourceId = resourceId
                    },
                    cancellationToken);
            }

            await context.SaveChangesAsync(cancellationToken);
            return Result<bool>.Success(true);
        }
        catch (Exception ex)
        {
            Log.Error($"EventBookResources: {ex.Message}", ex);
            return Error.ServerError;
        }
    }
}

using Api.Constants;
using Api.Extentions;
