namespace Api.EndPoint.Calendar;

/// <summary>Endpoints for calendar resources and event bookings (Group J).</summary>
public class CalendarResourcesEndPoint : ICarterModule
{
    /// <inheritdoc />
    public void AddRoutes(IEndpointRouteBuilder app)
    {
        app.MapGet("/Calendar/Resources", async (
            ISender sender,
            CancellationToken cancellationToken) =>
        {
            var res = await sender.Send(new ResourcesListQuery(), cancellationToken);
            return CalendarProblemResults.FromResult(res);
        })
        .WithName("ResourcesList")
        .Produces<List<CalendarResourceDto>>(StatusCodes.Status200OK)
        .ProducesProblem(StatusCodes.Status400BadRequest)
        .WithSummary("J1 — List calendar resources")
        .RequireRateLimiting(RateLimitConst.RateFix)
        .RequireAuthorization();

        app.MapPost("/Calendar/Resources", async (
            [FromBody] CalendarResourceCreateDto request,
            ISender sender,
            CancellationToken cancellationToken) =>
        {
            var res = await sender.Send(new ResourceCreateCommand(request), cancellationToken);
            return CalendarProblemResults.FromResult(res);
        })
        .WithName("ResourceCreate")
        .Produces<int>(StatusCodes.Status200OK)
        .ProducesProblem(StatusCodes.Status400BadRequest)
        .ProducesProblem(StatusCodes.Status403Forbidden)
        .WithSummary("J2 — Create calendar resource (admin)")
        .RequireRateLimiting(RateLimitConst.RateFix)
        .RequireAuthorization();

        app.MapPut("/Calendar/Resources", async (
            [FromBody] CalendarResourceUpdateDto request,
            ISender sender,
            CancellationToken cancellationToken) =>
        {
            var res = await sender.Send(new ResourceUpdateCommand(request), cancellationToken);
            return CalendarProblemResults.FromResult(res);
        })
        .WithName("ResourceUpdate")
        .Produces<bool>(StatusCodes.Status200OK)
        .ProducesProblem(StatusCodes.Status400BadRequest)
        .ProducesProblem(StatusCodes.Status403Forbidden)
        .ProducesProblem(StatusCodes.Status404NotFound)
        .WithSummary("J3 — Update calendar resource (admin)")
        .RequireRateLimiting(RateLimitConst.RateFix)
        .RequireAuthorization();

        app.MapDelete("/Calendar/Resources/{id:int}", async (
            int id,
            ISender sender,
            CancellationToken cancellationToken) =>
        {
            var res = await sender.Send(new ResourceDeleteCommand(id), cancellationToken);
            return CalendarProblemResults.FromResult(res);
        })
        .WithName("ResourceDelete")
        .Produces<bool>(StatusCodes.Status200OK)
        .ProducesProblem(StatusCodes.Status403Forbidden)
        .ProducesProblem(StatusCodes.Status404NotFound)
        .WithSummary("J4 — Soft-delete calendar resource (admin)")
        .RequireRateLimiting(RateLimitConst.RateFix)
        .RequireAuthorization();

        app.MapPost("/Calendar/Event/Resources", async (
            [FromBody] EventBookResourcesDto request,
            ISender sender,
            CancellationToken cancellationToken) =>
        {
            var res = await sender.Send(new EventBookResourcesCommand(request), cancellationToken);
            return CalendarProblemResults.FromResult(res);
        })
        .WithName("EventBookResources")
        .Produces<bool>(StatusCodes.Status200OK)
        .ProducesProblem(StatusCodes.Status400BadRequest)
        .ProducesProblem(StatusCodes.Status403Forbidden)
        .ProducesProblem(StatusCodes.Status404NotFound)
        .ProducesProblem(StatusCodes.Status409Conflict)
        .WithSummary("J5 — Book resources on an event")
        .RequireRateLimiting(RateLimitConst.RateFix)
        .RequireAuthorization();
    }
}

