using System.Globalization;
using System.Text.RegularExpressions;
using Application.Errors;
using Domain.Models;

namespace Application.Features.CalendarSupport;

/// <summary>Helpers for scheduling links and guest phone validation.</summary>
public static class SchedulingLinkHelper
{
    private static readonly Regex PhoneRegex = new(@"^\+?\d{10,15}$", RegexOptions.Compiled);

    /// <summary>Validates guest phone format.</summary>
    public static Error? ValidatePhone(string? phone) =>
        string.IsNullOrWhiteSpace(phone) || !PhoneRegex.IsMatch(phone.Trim())
            ? SchedulingLinkErrors.InvalidGuestPhone
            : null;

    /// <summary>Validates guest name.</summary>
    public static Error? ValidateGuestName(string? name) =>
        string.IsNullOrWhiteSpace(name) || name.Trim().Length < 2
            ? SchedulingLinkErrors.GuestNameRequired
            : null;

    /// <summary>Parses HH:mm into TimeSpan.</summary>
    public static bool TryParseHm(string? value, out TimeSpan time)
    {
        time = default;
        return !string.IsNullOrWhiteSpace(value)
               && TimeSpan.TryParseExact(value.Trim(), @"hh\:mm", CultureInfo.InvariantCulture, out time);
    }

    /// <summary>Serializes weekdays to CSV.</summary>
    public static string? SerializeWeekDays(IEnumerable<int>? days)
    {
        if (days is null)
            return null;

        var list = days.Distinct().OrderBy(x => x).ToList();
        return list.Count == 0 ? null : string.Join(',', list);
    }

    /// <summary>Parses weekday CSV.</summary>
    public static List<int> ParseWeekDays(string? csv)
    {
        if (string.IsNullOrWhiteSpace(csv))
            return [];

        return csv.Split(',', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries)
            .Select(x => int.TryParse(x, out var d) ? d : -1)
            .Where(x => x is >= 0 and <= 6)
            .Distinct()
            .OrderBy(x => x)
            .ToList();
    }

    /// <summary>Returns whether the link is currently valid for public use.</summary>
    public static bool IsLinkActive(CalendarSchedulingLink link, DateTime now)
    {
        if (link.ValidFrom.HasValue && now < link.ValidFrom.Value)
            return false;
        if (link.ValidTo.HasValue && now > link.ValidTo.Value)
            return false;
        return true;
    }

    /// <summary>Returns whether a candidate slot start matches weekday/window rules.</summary>
    public static bool MatchesLinkWindow(CalendarSchedulingLink link, DateTime start, DateTime end)
    {
        var weekDays = ParseWeekDays(link.AllowedWeekDays);
        if (weekDays.Count > 0 && !weekDays.Contains((int)start.DayOfWeek))
            return false;

        if (link.DailyStart.HasValue && link.DailyEnd.HasValue)
        {
            var tod = start.TimeOfDay;
            var endTod = end.TimeOfDay;
            if (tod < link.DailyStart.Value || endTod > link.DailyEnd.Value)
                return false;
        }

        return true;
    }
}

