    {
        RuleFor(x => x.Model.Title)
            .NotEmpty().WithMessage("عنوان لینک الزامی است")
            .MinimumLength(2).WithMessage("عنوان باید حداقل ۲ کاراکتر باشد")
            .MaximumLength(200).WithMessage("عنوان نباید بیشتر از ۲۰۰ کاراکتر باشد");

        RuleFor(x => x.Model.DurationMinutes)
            .InclusiveBetween(5, 180).WithMessage("مدت جلسه باید بین ۵ تا ۱۸۰ دقیقه باشد");
