using Application.Errors;
using Application.Features.CalendarSupport;
using Application.Services;
using Domain.Models;

namespace Application.Features.Command;

/// <summary>Handles creating a scheduling link (K1).</summary>
public class SchedulingLinkCreateCommandHandler(
    IApplicationDbContext context,
    ICurrentUserService currentUser)
    : IRequestHandler<SchedulingLinkCreateCommand, Result<int>>
{
    /// <inheritdoc />
    public async Task<Result<int>> Handle(
        SchedulingLinkCreateCommand request,
        CancellationToken cancellationToken)
    {
        try
        {
            var model = request.Model;

            if (string.IsNullOrWhiteSpace(model.Title) || model.Title.Trim().Length < 2)
                return SchedulingLinkErrors.TitleRequired;

            if (model.DurationMinutes is < 5 or > 180)
                return SchedulingLinkErrors.InvalidDuration;

            if (model.ValidFrom.HasValue && model.ValidTo.HasValue
                && model.ValidTo.Value <= model.ValidFrom.Value)
                return SchedulingLinkErrors.InvalidValidityWindow;

            TimeSpan? dailyStart = null;
            TimeSpan? dailyEnd = null;
            if (model.DailyTimeWindow is not null)
            {
                if (!SchedulingLinkHelper.TryParseHm(model.DailyTimeWindow.Start, out var s)
                    || !SchedulingLinkHelper.TryParseHm(model.DailyTimeWindow.End, out var e)
                    || e <= s)
                    return SchedulingLinkErrors.InvalidDailyWindow;

                dailyStart = s;
                dailyEnd = e;
            }

            if (model.AllowedWeekDays is not null
                && model.AllowedWeekDays.Any(d => d is < 0 or > 6))
                return SchedulingLinkErrors.InvalidWeekDays;

            var entity = new CalendarSchedulingLink
            {
                OwnerUserId = currentUser.UserId(),
                Token = Guid.NewGuid().ToString("N"),
                Title = model.Title.Trim(),
                DurationMinutes = model.DurationMinutes,
                ValidFrom = model.ValidFrom,
                ValidTo = model.ValidTo,
                AllowedWeekDays = SchedulingLinkHelper.SerializeWeekDays(model.AllowedWeekDays),
                DailyStart = dailyStart,
                DailyEnd = dailyEnd
            };

            await context.CalendarSchedulingLinks.AddAsync(entity, cancellationToken);
            await context.SaveChangesAsync(cancellationToken);
            return Result<int>.Success(entity.Id);
        }
        catch (Exception ex)
        {
            Log.Error($"SchedulingLinkCreate: {ex.Message}", ex);
            return Error.ServerError;
        }
    }
}

