/// <summary>Query to list current user's scheduling links (K2).</summary>
public record SchedulingLinksListQuery() : IRequest<Result<List<SchedulingLinkDto>>>;

/// <summary>Handles listing scheduling links (K2).</summary>
public class SchedulingLinksListQueryHandler(
    IApplicationDbContext context,
    ICurrentUserService currentUser)
    : IRequestHandler<SchedulingLinksListQuery, Result<List<SchedulingLinkDto>>>
{
    /// <inheritdoc />
    public async Task<Result<List<SchedulingLinkDto>>> Handle(
        SchedulingLinksListQuery request,
        CancellationToken cancellationToken)
    {
        try
        {
            var ownerId = currentUser.UserId();
            var items = await context.CalendarSchedulingLinks
                .AsNoTracking()
                .Where(x => x.OwnerUserId == ownerId)
                .OrderByDescending(x => x.Id)
                .ToListAsync(cancellationToken);

            var dtos = items.Select(x =>
            {
                DailyTimeWindowDto? window = null;
                if (x.DailyStart.HasValue && x.DailyEnd.HasValue)
                {
                    window = new DailyTimeWindowDto
                    {
                        Start = x.DailyStart.Value.ToString(@"hh\:mm"),
                        End = x.DailyEnd.Value.ToString(@"hh\:mm")
                    };
                }

                return new SchedulingLinkDto
                {
                    Id = x.Id,
                    Token = x.Token,
                    Title = x.Title,
                    DurationMinutes = x.DurationMinutes,
                    ValidFrom = x.ValidFrom,
                    ValidTo = x.ValidTo,
                    AllowedWeekDays = SchedulingLinkHelper.ParseWeekDays(x.AllowedWeekDays),
                    DailyTimeWindow = window
                };
            }).ToList();

            return Result<List<SchedulingLinkDto>>.Success(dtos);
        }
        catch (Exception ex)
        {
            Log.Error($"SchedulingLinksList: {ex.Message}", ex);
            return Error.ServerError;
        }
    }
}

