public class SchedulingLinkDeleteCommandHandler(
    IApplicationDbContext context,
    ICurrentUserService currentUser)
    : IRequestHandler<SchedulingLinkDeleteCommand, Result<bool>>
{
    /// <inheritdoc />
    public async Task<Result<bool>> Handle(
        SchedulingLinkDeleteCommand request,
        CancellationToken cancellationToken)
    {
        try
        {
            var entity = await context.CalendarSchedulingLinks
                .FirstOrDefaultAsync(x => x.Id == request.Id, cancellationToken);

            if (entity is null)
                return SchedulingLinkErrors.NotFound;

            if (entity.OwnerUserId != currentUser.UserId())
                return SchedulingLinkErrors.DeleteForbidden;

            entity.IsDeleted = true;
            entity.DeleteDate = DateTime.Now;

            await context.SaveChangesAsync(cancellationToken);
            return Result<bool>.Success(true);
        }
        catch (Exception ex)
        {
            Log.Error($"SchedulingLinkDelete: {ex.Message}", ex);
            return Error.ServerError;
        }
    }
}

