namespace Application.Features.Query;

/// <summary>Public query for scheduling-link availability (K4).</summary>
public record SchedulingLinkAvailabilityQuery(string Token, DateTime From, DateTime To)
    : IRequest<Result<List<SchedulingAvailabilitySlotDto>>>;

/// <summary>Handles public availability for a scheduling link (K4).</summary>
public class SchedulingLinkAvailabilityQueryHandler(IApplicationDbContext context)
    : IRequestHandler<SchedulingLinkAvailabilityQuery, Result<List<SchedulingAvailabilitySlotDto>>>
{
    private const int StepMinutes = 15;
    private const int MaxSlots = 40;

    /// <inheritdoc />
    public async Task<Result<List<SchedulingAvailabilitySlotDto>>> Handle(
        SchedulingLinkAvailabilityQuery request,
        CancellationToken cancellationToken)
    {
        try
        {
            if (string.IsNullOrWhiteSpace(request.Token))
                return SchedulingLinkErrors.NotFound;

            var rangeError = CalendarAccessHelper.ValidateTimeRange(request.From, request.To);
            if (rangeError is not null)
                return rangeError;

            var link = await context.CalendarSchedulingLinks
                .AsNoTracking()
                .FirstOrDefaultAsync(x => x.Token == request.Token.Trim(), cancellationToken);

            if (link is null || !SchedulingLinkHelper.IsLinkActive(link, DateTime.UtcNow))
                return SchedulingLinkErrors.NotFound;

            var ownerId = link.OwnerUserId;
            var duration = TimeSpan.FromMinutes(link.DurationMinutes);
            var step = TimeSpan.FromMinutes(StepMinutes);

            var events = await context.CalendarEvents
                .AsNoTracking()
                .Include(x => x.Recurrence)
                .Include(x => x.Exceptions)
                .Include(x => x.Participants)
                .Where(x => x.Status == EventStatus.Confirmed)
                .Where(x =>
                    x.CreatedByUserId == ownerId
                    || x.Participants.Any(p =>
                        p.UserId == ownerId && p.Response != ParticipantResponse.Declined))
                .ToListAsync(cancellationToken);

            var busy = events
                .SelectMany(evt => CalendarBusyHelper.GetBusySlots(evt, ownerId, request.From, request.To))
                .OrderBy(x => x.StartAt)
                .Select(x => (x.StartAt, x.EndAt))
                .ToList();

            busy = Merge(busy);

            var slots = new List<SchedulingAvailabilitySlotDto>();
            for (var cursor = request.From; cursor + duration <= request.To; cursor += step)
            {
                cancellationToken.ThrowIfCancellationRequested();
                var end = cursor + duration;

                if (!SchedulingLinkHelper.MatchesLinkWindow(link, cursor, end))
                    continue;

                if (Overlaps(busy, cursor, end))
                    continue;

                slots.Add(new SchedulingAvailabilitySlotDto { StartAt = cursor, EndAt = end });
                if (slots.Count >= MaxSlots)
                    break;
            }

            return Result<List<SchedulingAvailabilitySlotDto>>.Success(slots);
        }
        catch (Exception ex)
        {
            Log.Error($"SchedulingLinkAvailability: {ex.Message}", ex);
            return Error.ServerError;
        }
    }

    private static List<(DateTime Start, DateTime End)> Merge(List<(DateTime Start, DateTime End)> items)
    {
        if (items.Count == 0)
            return items;

        var result = new List<(DateTime Start, DateTime End)>();
        var cur = items[0];
        for (var i = 1; i < items.Count; i++)
        {
            var next = items[i];
            if (next.Start <= cur.End)
                cur = (cur.Start, next.End > cur.End ? next.End : cur.End);
            else
            {
                result.Add(cur);
                cur = next;
            }
        }

        result.Add(cur);
        return result;
    }

    private static bool Overlaps(List<(DateTime Start, DateTime End)> busy, DateTime start, DateTime end) =>
        busy.Any(b => start < b.End && end > b.Start);
}

