namespace Application.Features.Command;

/// <summary>Command to book a slot via public scheduling link (K5).</summary>
public record SchedulingLinkBookCommand(string Token, SchedulingLinkBookDto Model)
    : IRequest<Result<int>>;

/// <summary>Validates <see cref="SchedulingLinkBookCommand"/>.</summary>
public class SchedulingLinkBookCommandValidator : AbstractValidator<SchedulingLinkBookCommand>
{
    /// <summary>Initializes validator rules.</summary>
    public SchedulingLinkBookCommandValidator()
    {
        RuleFor(x => x.Token).NotEmpty().WithMessage("توکن لینک الزامی است");
        RuleFor(x => x.Model.GuestFullName)
            .NotEmpty().WithMessage("نام مهمان الزامی است")
            .MinimumLength(2).WithMessage("نام مهمان باید حداقل ۲ کاراکتر باشد");
        RuleFor(x => x.Model.GuestPhoneNumber).NotEmpty().WithMessage("شماره تلفن مهمان الزامی است");
    }
}

/// <summary>Handles public booking via scheduling link (K5).</summary>
public class SchedulingLinkBookCommandHandler(IApplicationDbContext context)
    : IRequestHandler<SchedulingLinkBookCommand, Result<int>>
{
    /// <inheritdoc />
    public async Task<Result<int>> Handle(
        SchedulingLinkBookCommand request,
        CancellationToken cancellationToken)
    {
        try
        {
            var nameError = SchedulingLinkHelper.ValidateGuestName(request.Model.GuestFullName);
            if (nameError is not null)
                return nameError;

            var phoneError = SchedulingLinkHelper.ValidatePhone(request.Model.GuestPhoneNumber);
            if (phoneError is not null)
                return phoneError;

            var link = await context.CalendarSchedulingLinks
                .FirstOrDefaultAsync(x => x.Token == request.Token.Trim(), cancellationToken);

            if (link is null || !SchedulingLinkHelper.IsLinkActive(link, DateTime.UtcNow))
                return SchedulingLinkErrors.NotFound;

            var start = request.Model.StartAt;
            var end = start.AddMinutes(link.DurationMinutes);

            if (!SchedulingLinkHelper.MatchesLinkWindow(link, start, end))
                return SchedulingLinkErrors.SlotNotAvailable;

            var conflictName = await EventConflictHelper.FindConflictUserNameAsync(
                context,
                [link.OwnerUserId],
                start,
                end,
                null,
                cancellationToken);

            if (conflictName is not null)
                return SchedulingLinkErrors.SlotNotAvailable;

            var personal = await context.Calendars
                .FirstOrDefaultAsync(
                    x => x.Type == CalendarType.Personal
                         && x.OwnerUserId == link.OwnerUserId
                         && x.IsDefault,
                    cancellationToken);

            if (personal is null)
            {
                personal = Calendar.CreateDefaultPersonal(link.OwnerUserId);
                await context.Calendars.AddAsync(personal, cancellationToken);
                await context.SaveChangesAsync(cancellationToken);
            }

            var calendarEvent = new CalendarEvent
            {
                CalendarId = personal.Id,
                CreatedByUserId = link.OwnerUserId,
                Title = link.Title,
                Type = EventType.Meeting,
                Status = EventStatus.Confirmed,
                StartAt = start,
                EndAt = end,
                IsAllDay = false,
                IsPersonal = false,
                VisibleOnlyToParticipants = false
            };

            await context.CalendarEvents.AddAsync(calendarEvent, cancellationToken);
            await context.SaveChangesAsync(cancellationToken);

            await context.GuestContacts.AddAsync(new GuestContact
            {
                EventId = calendarEvent.Id,
                CreatedByUserId = link.OwnerUserId,
                FullName = request.Model.GuestFullName.Trim(),
                PhoneNumber = request.Model.GuestPhoneNumber.Trim()
            }, cancellationToken);

            await context.SaveChangesAsync(cancellationToken);
            return Result<int>.Success(calendarEvent.Id);
        }
        catch (Exception ex)
        {
            Log.Error($"SchedulingLinkBook: {ex.Message}", ex);
            return Error.ServerError;
        }
    }
}

