using Api.Constants;
using Api.Extentions;
using Application.DTOs.Calendar;
using Application.Features.Command;
using Application.Features.Query;

namespace Api.EndPoint.Calendar;

/// <summary>Endpoints for scheduling links and guest invites (Group K).</summary>
public class CalendarSchedulingLinksEndPoint : ICarterModule
{
    /// <inheritdoc />
    public void AddRoutes(IEndpointRouteBuilder app)
    {
        app.MapPost("/Calendar/SchedulingLinks", async (
            [FromBody] SchedulingLinkCreateDto request,
            ISender sender,
            CancellationToken cancellationToken) =>
        {
            var res = await sender.Send(new SchedulingLinkCreateCommand(request), cancellationToken);
            return CalendarProblemResults.FromResult(res);
        })
        .WithName("SchedulingLinkCreate")
        .Produces<int>(StatusCodes.Status200OK)
        .ProducesProblem(StatusCodes.Status400BadRequest)
        .WithSummary("K1 — Create scheduling link")
        .RequireRateLimiting(RateLimitConst.RateFix)
        .RequireAuthorization();

        app.MapGet("/Calendar/SchedulingLinks", async (
            ISender sender,
            CancellationToken cancellationToken) =>
        {
            var res = await sender.Send(new SchedulingLinksListQuery(), cancellationToken);
            return CalendarProblemResults.FromResult(res);
        })
        .WithName("SchedulingLinksList")
        .Produces<List<SchedulingLinkDto>>(StatusCodes.Status200OK)
        .WithSummary("K2 — List my scheduling links")
        .RequireRateLimiting(RateLimitConst.RateFix)
        .RequireAuthorization();

        app.MapDelete("/Calendar/SchedulingLinks/{id:int}", async (
            int id,
            ISender sender,
            CancellationToken cancellationToken) =>
        {
            var res = await sender.Send(new SchedulingLinkDeleteCommand(id), cancellationToken);
            return CalendarProblemResults.FromResult(res);
        })
        .WithName("SchedulingLinkDelete")
        .Produces<bool>(StatusCodes.Status200OK)
        .ProducesProblem(StatusCodes.Status403Forbidden)
        .ProducesProblem(StatusCodes.Status404NotFound)
        .WithSummary("K3 — Soft-delete scheduling link")
        .RequireRateLimiting(RateLimitConst.RateFix)
        .RequireAuthorization();

        app.MapGet("/Calendar/SchedulingLinks/{token}/Availability", async (
            string token,
            DateTime from,
            DateTime to,
            ISender sender,
            CancellationToken cancellationToken) =>
        {
            var res = await sender.Send(
                new SchedulingLinkAvailabilityQuery(token, from, to),
                cancellationToken);
            return CalendarProblemResults.FromResult(res);
        })
        .WithName("SchedulingLinkAvailability")
        .Produces<List<SchedulingAvailabilitySlotDto>>(StatusCodes.Status200OK)
        .ProducesProblem(StatusCodes.Status404NotFound)
        .WithSummary("K4 — Public availability for scheduling link")
        .RequireRateLimiting(RateLimitConst.RateFix)
        .AllowAnonymous();

        app.MapPost("/Calendar/SchedulingLinks/{token}/Book", async (
            string token,
            [FromBody] SchedulingLinkBookDto request,
            ISender sender,
            CancellationToken cancellationToken) =>
        {
