                .AsNoTracking()
                .AnyAsync(x => x.EventId == calendarEvent.Id, cancellationToken);

            if (exists)
                return MinutesErrors.AlreadyExists;

            var entity = new MeetingMinutes
            {
                EventId = calendarEvent.Id,
                CreatedByUserId = userId,
                OverallOutcome = string.IsNullOrWhiteSpace(request.Model.OverallOutcome)
                    ? null
                    : request.Model.OverallOutcome.Trim()
            };

            await context.MeetingMinutes.AddAsync(entity, cancellationToken);
            await context.SaveChangesAsync(cancellationToken);
            return Result<int>.Success(entity.Id);
