namespace Application.Features.Query;

/// <summary>Query to get minutes for an event (L2).</summary>
public record MeetingMinutesGetByEventQuery(int EventId) : IRequest<Result<MeetingMinutesDto>>;

/// <summary>Handles loading meeting minutes (L2).</summary>
public class MeetingMinutesGetByEventQueryHandler(
    IApplicationDbContext context,
    ICurrentUserService currentUser)
    : IRequestHandler<MeetingMinutesGetByEventQuery, Result<MeetingMinutesDto>>
{
    /// <inheritdoc />
    public async Task<Result<MeetingMinutesDto>> Handle(
        MeetingMinutesGetByEventQuery request,
        CancellationToken cancellationToken)
    {
        try
        {
            var userId = currentUser.UserId();
            var calendarEvent = await context.CalendarEvents
                .AsNoTracking()
                .Include(x => x.Participants)
                .FirstOrDefaultAsync(x => x.Id == request.EventId, cancellationToken);

            if (calendarEvent is null)
                return EventErrors.NotFound;

            if (!CalendarAccessHelper.CanViewEvent(calendarEvent, userId))
                return MinutesErrors.ViewForbidden;

            var minutes = await context.MeetingMinutes
                .AsNoTracking()
                .Include(x => x.AgendaItems)
                .Include(x => x.Decisions)
                .Include(x => x.Actions)
                .ThenInclude(a => a.AssigneeUser)
                .FirstOrDefaultAsync(x => x.EventId == request.EventId, cancellationToken);

            if (minutes is null)
                return MinutesErrors.NotFound;

            return Result<MeetingMinutesDto>.Success(Map(minutes));
        }
        catch (Exception ex)
        {
            Log.Error($"MeetingMinutesGet: {ex.Message}", ex);
            return Error.ServerError;
        }
    }

    internal static MeetingMinutesDto Map(Domain.Models.MeetingMinutes minutes) =>
        new()
        {
            Id = minutes.Id,
            EventId = minutes.EventId,
            OverallOutcome = minutes.OverallOutcome,
            AgendaItems = minutes.AgendaItems
                .Where(x => !x.IsDeleted)
                .OrderBy(x => x.SortOrder)
                .Select(x => new MinutesTextItemDto
                {
                    Id = x.Id,
                    SortOrder = x.SortOrder,
                    Text = x.Text
                }).ToList(),
            Decisions = minutes.Decisions
                .Where(x => !x.IsDeleted)
                .OrderBy(x => x.SortOrder)
                .Select(x => new MinutesTextItemDto
                {
                    Id = x.Id,
                    SortOrder = x.SortOrder,
                    Text = x.Text
                }).ToList(),
            Actions = minutes.Actions
                .Where(x => !x.IsDeleted)
                .OrderBy(x => x.Id)
                .Select(x => new MinutesActionDto
                {
                    Id = x.Id,
                    Title = x.Title,
                    AssigneeUserId = x.AssigneeUserId,
                    AssigneeFullName = x.AssigneeUser?.Name,
                    DueDate = x.DueDate,
                    IsCompleted = x.IsCompleted,
                    NotCompletedReason = x.NotCompletedReason,
                    CompletedAt = x.CompletedAt
                }).ToList()
        };
}

