public record MeetingMinutesUpdateCommand(MeetingMinutesUpdateDto Model) : IRequest<Result<bool>>;

/// <summary>Validates <see cref="MeetingMinutesUpdateCommand"/>.</summary>
public class MeetingMinutesUpdateCommandValidator : AbstractValidator<MeetingMinutesUpdateCommand>
{
    /// <summary>Initializes validator rules.</summary>
    public MeetingMinutesUpdateCommandValidator()
    {
        RuleFor(x => x.Model.Id).GreaterThan(0);
        RuleFor(x => x.Model.OverallOutcome).MaximumLength(4000)
            .When(x => x.Model.OverallOutcome is not null);
    }
}

/// <summary>Handles updating minutes content (L3).</summary>
public class MeetingMinutesUpdateCommandHandler(
    IApplicationDbContext context,
    ICurrentUserService currentUser)
    : IRequestHandler<MeetingMinutesUpdateCommand, Result<bool>>
{
    /// <inheritdoc />
    public async Task<Result<bool>> Handle(
        MeetingMinutesUpdateCommand request,
        CancellationToken cancellationToken)
    {
        try
        {
            var userId = currentUser.UserId();
            var minutes = await context.MeetingMinutes
                .Include(x => x.Event).ThenInclude(e => e.Calendar)
                .Include(x => x.AgendaItems)
                .Include(x => x.Decisions)
                .FirstOrDefaultAsync(x => x.Id == request.Model.Id, cancellationToken);

            if (minutes is null)
                return MinutesErrors.NotFound;

            var positionIds = await CalendarAccessHelper.GetUserPositionIdsAsync(
                context, userId, cancellationToken);

            if (!await CalendarAccessHelper.CanEditEventAsync(
                    minutes.Event, userId, currentUser, positionIds, cancellationToken))
                return MinutesErrors.EditForbidden;

            minutes.OverallOutcome = string.IsNullOrWhiteSpace(request.Model.OverallOutcome)
                ? null
                : request.Model.OverallOutcome.Trim();

            foreach (var item in minutes.AgendaItems.Where(x => !x.IsDeleted))
            {
                item.IsDeleted = true;
                item.DeleteDate = DateTime.Now;
            }

            foreach (var item in minutes.Decisions.Where(x => !x.IsDeleted))
            {
                item.IsDeleted = true;
                item.DeleteDate = DateTime.Now;
            }

            var agenda = request.Model.AgendaItems ?? [];
            for (var i = 0; i < agenda.Count; i++)
            {
                var text = agenda[i]?.Trim();
                if (string.IsNullOrWhiteSpace(text))
                    continue;

                await context.MinutesAgendaItems.AddAsync(new MinutesAgendaItem
                {
                    MinutesId = minutes.Id,
                    SortOrder = i,
                    Text = text.Length > 1000 ? text[..1000] : text
                }, cancellationToken);
            }

            var decisions = request.Model.Decisions ?? [];
            for (var i = 0; i < decisions.Count; i++)
            {
                var text = decisions[i]?.Trim();
                if (string.IsNullOrWhiteSpace(text))
                    continue;

                await context.MinutesDecisions.AddAsync(new MinutesDecision
                {
                    MinutesId = minutes.Id,
                    SortOrder = i,
                    Text = text.Length > 2000 ? text[..2000] : text
                }, cancellationToken);
            }

            await context.SaveChangesAsync(cancellationToken);
            return Result<bool>.Success(true);
        }
        catch (Exception ex)
        {
            Log.Error($"MeetingMinutesUpdate: {ex.Message}", ex);
            return Error.ServerError;
        }
    }
}

