/// <summary>Handles updating minutes action status (L5).</summary>
public class MinutesActionStatusCommandHandler(
    IApplicationDbContext context,
    ICurrentUserService currentUser)
    : IRequestHandler<MinutesActionStatusCommand, Result<bool>>
{
    /// <inheritdoc />
    public async Task<Result<bool>> Handle(
        MinutesActionStatusCommand request,
        CancellationToken cancellationToken)
    {
        try
        {
            var userId = currentUser.UserId();
            var action = await context.MinutesActions
                .Include(x => x.Minutes).ThenInclude(m => m.Event).ThenInclude(e => e.Calendar)
                .FirstOrDefaultAsync(x => x.Id == request.Model.Id, cancellationToken);

            if (action is null)
                return MinutesErrors.ActionNotFound;

            var positionIds = await CalendarAccessHelper.GetUserPositionIdsAsync(
                context, userId, cancellationToken);

            if (!await CalendarAccessHelper.CanEditEventAsync(
                    action.Minutes.Event, userId, currentUser, positionIds, cancellationToken))
                return MinutesErrors.EditForbidden;

            if (request.Model.IsCompleted)
            {
                action.IsCompleted = true;
                action.NotCompletedReason = null;
                action.CompletedAt = DateTime.Now;
            }
            else
            {
                if (string.IsNullOrWhiteSpace(request.Model.NotCompletedReason))
                    return MinutesErrors.ReasonRequired;

                action.IsCompleted = false;
                action.NotCompletedReason = request.Model.NotCompletedReason.Trim();
                action.CompletedAt = null;
            }

            await context.SaveChangesAsync(cancellationToken);
            return Result<bool>.Success(true);
        }
        catch (Exception ex)
        {
            Log.Error($"MinutesActionStatus: {ex.Message}", ex);
            return Error.ServerError;
        }
    }
}

